MultiLanguageSpellData['nl'][466011] = {name = "Flarendo de Furious", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De VIP van VIP's in het Gallagio heeft zijn voordelen, inclusief de sleutels van deze voormalige koning van Carnage. Met geavanceerde goblintechnologie kan hij meer dan 100 meter per liter bereiken!\"\nVerkoper:\nAndo de Gat\nGebied:\nBevrijding van Ondermijning\nKosten:\n777"}
MultiLanguageSpellData['nl'][466012] = {name = "Onweersbui", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Gevonden van de tribunes van de Ketel tijdens een bijzonder gruwelijke botsing. Toen Torq gevraagd werd of het een blindganger was, antwoordde hij simpelweg: 'Waarschijnlijk?'\"\nVerkoper:\nAndo de Gat\nGebied:\nBevrijding van Ondermijning\nKosten:\n500"}
