MultiLanguageSpellData['nl'][466340] = {name = "Scatterblastbussen", additional_info = "Onbeperkt bereik\n3 sec gegoten\n[q]Gallywix kanonnen zijn huidige doelwit veroorzaken 20950056 Fysieke schade. Deze aanval kan niet worden ontlopen of geplaagd.\n\nDit blast bovendien spelers in een frontale kegel veroorzaken 46083683 Brandschade en verhoogt Scatterblast Canisters schade genomen door 100% gedurende 30 sec. Deze schade splitst gelijkmatig tussen de spelers.\n\nAlle doelen raken getroffen door Mechengineer's Canisters.\n\nAls dit mislukt om ten minste 3 doelen te raken alle spelers lijden het volledige effect."}
