MultiLanguageSpellData['nl'][466990] = {name = "Verdovend vuur", additional_info = "[q]Beast Mastery\nTerwijl Call of the Wild actief is, geef je je over aan de duisternis, waardoor je elke 4 seconden Verwelkende Vuur en Deathblow krijgt.\n\nVerdovend vuur\nCasting Black Arrow vuurt een spervuur van 2 extra zwarte pijlen op nabijgelegen doelen op 50% effectiviteit, prioriteit vijanden die niet worden beïnvloed door de schade van Black Arrow in de tijd effect.\n\nMarkmanschap\nTerwijl Trueshot actief is, geef je je over aan de duisternis, waardoor je Verdwijnende Vuur en Deathblow krijgt.\n\nVerdovend vuur\nCasting Black Arrow vuurt een spervuur van 2 extra zwarte pijlen op nabijgelegen doelen op 50% effectiviteit, prioriteit vijanden die niet worden beïnvloed door de schade van Black Arrow in de tijd effect."}
MultiLanguageSpellData['nl'][466991] = {name = "Verdovend vuur", additional_info = "Direct\n[q]Beast Mastery\nTerwijl Call of the Wild actief is, geef je je over aan de duisternis, waardoor je elke 4 seconden Verwelkende Vuur en Deathblow krijgt.\n\nVerdovend vuur\nCasting Black Arrow vuurt een spervuur van 2 extra zwarte pijlen op nabijgelegen doelen op 50% effectiviteit, prioriteit vijanden die niet worden beïnvloed door de schade van Black Arrow in de tijd effect.\n\nMarkmanschap\nTerwijl Trueshot actief is, geef je je over aan de duisternis, waardoor je Verdwijnende Vuur en Deathblow krijgt.\n\nVerdovend vuur\nCasting Black Arrow vuurt een spervuur van 2 extra zwarte pijlen op nabijgelegen doelen op 50% effectiviteit, prioriteit vijanden die niet worden beïnvloed door de schade van Black Arrow in de tijd effect."}
