MultiLanguageSpellData['nl'][467011] = {name = "Ego-controle", additional_info = "Onbeperkt bereik\nDirect\n[q]Gallywix geeft zijn huidige doelwit een 4-hit knokkel sandwich, waardoor 13416139 fysieke schade elke staking. Deze klappen kunnen niet worden ontlopen of gedragen.\n\nBovendien wordt 75% van de schade veroorzaakt als een Gecontroleerde Ego."}
MultiLanguageSpellData['nl'][467020] = {name = "Foute Zap", additional_info = "Onbeperkt bereik\nDirect\n[q]Rik's machine short circuits sturen een schok van elektriciteit door verschillende spelers, waardoor 1006210 Natuur schade. De elektriciteit blijft in hen gedurende 9 sec, het toebrengen van 670807 Natuurschade aan spelers binnen 5 yards elke 1,5 sec en het verhogen van de schade van de doelstelling Natuur genomen met 75% voor 9 sec."}
MultiLanguageSpellData['nl'][467021] = {name = "Klauw Frenzy", additional_info = "Melee-bereik\n1 sec gegoten\n[q]De caster gaat in een razernij, het toebrengen van fysieke schade aan de doelvijand elke 0,5 sec voor 3,4 sec."}
MultiLanguageSpellData['nl'][467024] = {name = "Kaja'Cola Carrier", additional_info = "[q]Mislaid Curiosities hebben nu een 35% kans om 1 Kaja'Cola te bevatten en eenmaal per delve roept Brann nu een Kaja'6-Pack op bij het maken van kampvuren.\n\nEr zijn verschillende Kaja'Cola smaken, en elk heeft zijn eigen effect dat van toepassing is wanneer verzameld."}
MultiLanguageSpellData['nl'][467026] = {name = "Goblomagnetische bounzing grenade", additional_info = "[q]Brann heeft een kans tijdens de strijd om een GMB granaat te gooien op een vijandelijke doel omgaan met matige Natuurschade met een 20% kans om te verdoven voor 1,5 sec. Dit heeft een kans van 25% om een nieuw doel te bereiken.\n\nDe granaat kan veilig op partijleden stuiteren."}
MultiLanguageSpellData['nl'][467029] = {name = "Impact Conversie Matrix", additional_info = "Brann activeert de conversiematrix voor 10 sec. Een klein percentage van alle partijschade behandeld gedurende deze tijd wordt omgezet in primaire status en splitsen tussen partij leden.\n\nNa de conversie matrix bevoegdheden naar beneden, de primaire status buff blijft gedurende 10 sec. Dit effect kan niet meer dan eenmaal per 2 minuten optreden."}
MultiLanguageSpellData['nl'][467031] = {name = "Zwarte bloedstroom", additional_info = "Onbeperkt bereik\nDirect\n[q]Black Blood giet uit het fabrieksplafond, waardoor 14 Schaduw schade elke 0,5 sec."}
MultiLanguageSpellData['nl'][467032] = {name = "Eibrand", additional_info = nil}
MultiLanguageSpellData['nl'][467033] = {name = "L00T RAID-R", additional_info = "[q]Elke 60 sec of 5 sec na het invoeren van de strijd, scan het milieu markeren van de verkeerde nieuwsgierigheid en het maken van vijanden onder 95% gezondheid nemen 4% meer schade voor 10 sec."}
MultiLanguageSpellData['nl'][467034] = {name = "Reverse Engineered Goblin Death Bomb", additional_info = "[q]Wanneer de gezondheid van een speler tijdens het gevecht onder de 50% daalt, gooit Brann een gigantische bom die ontploft bij impact.\n\nDe explosie klopt Back en vertraagt de omringende vijanden met 45% voor 5 sec en geneest nabijgelegen partijleden voor 35% van hun maximale gezondheid. Kan alleen elke 1,5 min. voorkomen."}
MultiLanguageSpellData['nl'][467035] = {name = "Comisch Grote Magneet", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, is er een 100% kans om te magnetiseren verworpen Plating aan partijleden die hen 5% van hun maximale gezondheid als een Shield die regenereert uit de strijd.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][467036] = {name = "Raketwerk voor biobrandstoffen", additional_info = "[q]Party leden zijn uitgerust met Biofuel Rocket Gear.\n\nBiobrandstof\nElke vijand gedood brandstoffen de Biofuel Raket Gear toenemende beweging Speed met 2% en Haste met 2% voor 10 sec, stapelen tot 10 keer."}
MultiLanguageSpellData['nl'][467037] = {name = "Pinged Augment Chip", additional_info = "De maximale gezondheid van [q]Brann wordt met 4% verhoogd en zijn schade en genezing met 20% verhoogd.\n\nTijdens het gevecht, Brann kan worden het doelwit door mechanische bots die fixeren op hem die kan worden vernietigd of verdoofd. Als ze Brann bereiken, zal hij 30% van zijn maximale gezondheid in schade lijden en verdoofd zijn gedurende 5 sec."}
