MultiLanguageSpellData['nl'][467718] = {name = "Bleekpijlen", additional_info = "40 yd bereik\nDirect\nVereist Ranged-wapen\n[q]Beast Mastery\nJe autoshot behandelt nu Schaduwschade, waardoor het Armor kan omzeilen.\n\nJouw autoshot heeft een kans van 20% om Deathblow toe te kennen.\n\nDeathblow\nDe afkoeling van Kill Shot is gereset. Uw volgende Kill Shot kan worden gebruikt op elk doel, ongeacht hun huidige gezondheid.\n\nMarkmanschap\nJe autoshot behandelt nu Schaduwschade, waardoor het Armor kan omzeilen.\n\nJouw autoshot heeft 8% kans om Deathblow toe te kennen.\n\nDeathblow\nDe afkoeling van Kill Shot is gereset. Uw volgende Kill Shot kan worden gebruikt op elk doel, ongeacht hun huidige gezondheid."}
