MultiLanguageSpellData['nl'][469831] = {name = "Maanstorm", additional_info = "100 yd bereik\nDirect\n[q]Marksmanschap\nElke 30 seconden, de afkoeling van Rapid Fire wordt gereset en uw volgende cast van Rapid Fire ook vuurt een hemelse pijl die een 12 yd radius Maanstorm roept op de locatie van het doel, dealen (100% van Attack Power) Arcane schade.\n\nVoor de volgende 12 sec, een willekeurige vijand beïnvloed door Sentinel binnen uw Maanstorm wordt getroffen voor (93,75% van Attack Power) Arcane schade elke 0.4 sec. Elk doelwit dat door dit effect wordt getroffen heeft 10% meer schade van u gedurende 8 sec.\n\nOverleving\nElke 30 seconden, de afkoeling van Wildfire Bomb wordt gereset en uw volgende cast van Wildfire Bomb ook vuurt een hemelse pijl die een 12 yd radius Maanstorm roept op de locatie van het doel, de handel (100% van Attack Power) Arcane schade.\n\nVoor de volgende 12 sec, een willekeurige vijand beïnvloed door Sentinel binnen uw Maanstorm wordt getroffen voor (93,75% van Attack Power) Arcane schade elke 0.4 sec. Elk doel getroffen door dit effect neemt 10% verhoogde schade van u en uw huisdier voor 8 sec."}
