MultiLanguageSpellData['nl'][470057] = {name = "Voltaic Blaze", additional_info = "40 yd bereik\nDirect\n[q]Onmiddellijk schokken het doel en 5 nabijgelegen vijanden met een brandende donder, waardoor (400% van Spell Power) Natuur schade en toepassing van Vlam Shock.\n\nGenereert 1 stapel van Maelstrom Wapen."}
MultiLanguageSpellData['nl'][470058] = {name = "Voltaic Blaze", additional_info = "Direct\n[q]Lightning Bolt en Chain Lightning hebben een hoge kans om uw volgende Vlam Shock worden Voltaic Blaze.\n\nVoltaic Blaze\nOnmiddellijk schokken het doel en 5 nabijgelegen vijanden met brandende donder, waardoor (400% van Spell Power) Natuurschade en het toepassen van Vlam Shock.\n\nGenereert 1 stapel van Maelstrom Wapen."}
MultiLanguageSpellData['nl'][470059] = {name = "Te veel Arcane", additional_info = "Channeled (1 uur cast)\n[q]Arcanotron lanceert een arcane bom op een nabijgelegen locatie. Als de bom de grond raakt, ontploft hij, waardoor 1755 Arcane schade toebrengt aan alle spelers.\n\nAls de bom een speler raakt veroorzaakt het 585 Arcane schade, verhoogt de speler arcane schade genomen met 10% voor 40 sec, en Arcanotron lanceert een andere bom die de grond sneller zal slaan.\n\nArcane Overcharge zal minder schade toebrengen aan de inval voor elke bom die werd gevangen."}
MultiLanguageSpellData['nl'][470061] = {name = "Statische lading", additional_info = "Onbeperkt bereik\nDirect\n[q]Torq's pak versterkt de elektrische ladingen binnen 70 meter. Tot de volgende Colossal Clash, een elektrische lading cursussen door spelers die in het bereik komen, waardoor 117391 Natuur schade elke 1 sec.. Bovendien, terwijl in het bereik, de lading groeit wanneer het doel beweegt en degradeert wanneer ze stationair. Bij maximale lading barst het uit in een Static Discharge."}
