MultiLanguageSpellData['nl'][470596] = {name = "Frostfire Burst", additional_info = "100 yd bereik\nDirect\n[q]Frost\nCasting Comet Storm zorgt ervoor dat uw volgende Ice Lance exploderen in een Frostfire Burst, dealen (265,6% van de Spell Power) Frostfire schade aan nabijgelegen vijanden. Schade verminderd boven 8 doelen.\n\nFrostfire Burst heeft 50% kans om Brain Freeze te verlenen.\n\nVuur\nCasting Meteor zorgt ervoor dat je volgende Vuur Blast explodeert in een Frostfire Burst, dealer (265,6% van Spell Power) Frostfire schade aan nabijgelegen vijanden. Schade verminderd boven 8 doelen.\n\nFrostfire Burst vermindert de afkoeling van Phoenix Flames met 5 sec."}
MultiLanguageSpellData['nl'][470598] = {name = "Smeek de Vuurheer", additional_info = "Direct\n[q]Wanneer Dagran minder dan 70% gezondheid, hij smeekt de Firelord voor hulp, het verkrijgen van een Shield dat 38722016 schade absorbeert.\n\nEen Avatar van Ragnaros voegt zich bij de strijd die 3872202 Brandschade toebrengt aan alle spelers. De schade wordt verder van het inslagpunt afgenomen."}
