MultiLanguageSpellData['nl'][471365] = {name = "Ondermijning", additional_info = "Direct\n[q]Aanbevolen vaardigheden: 375\n\nKanalen van Steamwheedle Runoff uit de verschillende pijpen. Het water wordt alleen bewoond door de sterkste Khaz Algar vis en wat er nog meer kan verdragen de scherpe vloeistof.\n\nZwembaden gevonden in deze zone:\n- Glimmerpool\n- Infused Ichor Spill\n- Steamwheedle Runoff\nBeroep:\nVisserij (225)"}
MultiLanguageSpellData['nl'][471366] = {name = "Trekboog", additional_info = "[q]Terwijl Trueshot actief is, breidt het verbruik van Precieze Shots de duur van Trueshot uit met 1,0 sec, tot 5,0 sec.\n\nDaarnaast verhoogt Trueshot nu de effectiviteit van Streamline met 50%."}
MultiLanguageSpellData['nl'][471368] = {name = "Blair's \"Goud\" Fish Exchange", additional_info = "5 yd bereik\n3.2 sec cast\n[q]Gelegen langs het centrale kanaal van The Vatworks, Blair Bass en haar team van Anglers hebben een bijzondere belangstelling genomen voor de lokale \"Goud\" Vis die de Undermine bewoont.\n\nKom langs om deel te nemen aan het behoud en verdien beloningen!\nBeroep:\nVisserij (225)"}
