MultiLanguageSpellData['nl'][472639] = {name = "Hogstrider", additional_info = "[q]Beast Mastery\nElke keer als uw Boar schade behandelt, wordt de schade van uw volgende Cobra Shot verhoogd met 25% en Cobra Shot slaat 1 extra doel. Stacks tot 4 keer.\n\nOverleving\nUw Boar oproepen verfrist de duur van Mongoose Fury.\n\nElke keer als uw Boar deals schade, heb je een 25% kans om een stapel van Mongoose Fury en Raptor Strike stakingen 1 extra doel te krijgen. Stacks tot 4 keer.\n\nMongoose Fury\nVerhoogt de schade van Mongoose Bite of Raptor Strike met 15% voor 16 sec, stapelen tot 5 keer."}
