MultiLanguageSpellData['nl'][474061] = {name = "Tankbuster", additional_info = "100 yd bereik\nDirect\n[q]De Geargrinder slaat in zijn huidige doel, het toebrengen van 12577630 Fysieke schade, kloppen ze Back en waardoor ze te bloeden voor 670807 fysieke schade elke 1,5 sec voor 25 sec. Bovendien heeft het doel 200% meer schade opgelopen dan Tank Buster voor 25 sec. Dit effect stapelt zich op.\n\nDe inspanning zorgt ervoor dat de Geargrinder een wolk van Uitlaat Fumes te verdrijven en lekken een olievlek die duurt 5 minuten."}
