MultiLanguageSpellData['nl'][474067] = {name = "Cast Queue: Bronzebeard's Bruine Beer", additional_info = "Onbeperkt bereik\nDirect\n[q]Brann roept de familiebeer op, die ten strijde trekt en vijanden in de lucht brengt.\n\nDe beer bereidt zich dan voor op een reeks van enorme stomps, het omgaan met schade, het vormen van een gebied dat de kans om te ontwijken verhoogt, en het verhogen van de maximale gezondheid."}
MultiLanguageSpellData['nl'][474069] = {name = "Noxious Spew", additional_info = "30 yd bereik\n2 sec gegoten\n[q]Spews schadelijke vuiligheid, het toebrengen van 838509 Natuur schade elke 1 sec aan spelers binnen."}
MultiLanguageSpellData['nl'][474070] = {name = "Cast Queue: Lightning Link", additional_info = "Onbeperkt bereik\nDirect\nDe apparatuur van [q]Brann is verbeterd met geavanceerde technische upgrades.\n\nElektro-geharged Shield\nEffectieve genezing gedaan aan Brann pulseert als natuur schade aan nabijgelegen vijanden.\n\nElektrisch geharkt pistool\nElk schot ontladingen een elektrische stroom, boog door nabijgelegen vijanden en het verminderen van hun aanval Speed. Brann genezen laadt zijn pistool op om meer schade aan te richten.\n\nElectro-geschut geweer\nElke vijand heeft een kans om neergeslagen te worden. Brann genezen laadt zijn geweer op om meer schade aan te richten."}
