MultiLanguageSpellData['nl'][474572] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nKaja'Cola Carrier\n[q]Mislaid Curiosities hebben nu een 35% kans om 1 Kaja'Cola te bevatten en eenmaal per delve roept Brann nu een Kaja'6-Pack op bij het maken van kampvuren.\n\nEr zijn verschillende Kaja'Cola smaken, en elk heeft zijn eigen effect dat van toepassing is wanneer verzameld.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474573] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nComisch Grote Magneet\n[q]Wanneer Brann Gathering Tools gebruikt, is er een 100 % kans om verwijderde Plating te magnetiseren aan partijleden die hen 5 % van hun maximale gezondheid als een Shield die regenereert uit de strijd.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474574] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nRaketwerk voor biobrandstoffen\n[q]Party leden zijn uitgerust met Biofuel Rocket Gear.\n\nBiobrandstof\nElke vijand gedood brandstoffen de Biofuel Raket Gear toenemende beweging Speed met 2 % en Haste met 2 % voor 10 sec, stapelen tot 10 keer.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474576] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nDriedimensionale bioprinter\n[q]Het beschadigen van een Elite schepsel onder de 40 procent gezondheid maakt een onvolmaakte kopie van het op 50 % macht om te vechten aan uw zijde. Slechts 1 exemplaar kan tegelijkertijd bestaan.\n\nHet apparaat kan defect maken van onvolmaakte kopieën van uw metgezel.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474577] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nOverdrive Pylon\n[q]Na 30 sec van de strijd, partyleden en Brann dealen 5 % meer schade en genezing voor 20 sec. Kan maar één keer per gevecht voorkomen.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474578] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nPacifist Rig\n[q]Tijdens het gevecht is een piloot aangewezen meer dan 8 sec voordat het luchtdruppelen van de Pacifist Rig MK-1 op hun locatie, waardoor ze immuun, waardoor ze controle over het platform voor 10 sec, en het slaan van Back nabijgelegen vijanden.\n\nJe hebt deze curio al in je collectie."}
