MultiLanguageSpellData['nl'][474591] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nPacifist Rig\n[q]Tijdens het gevecht wordt een piloot meer dan 8 sec aangewezen voordat het luchtdruppelen van de Pacifist Rig MK-2 op hun locatie, waardoor ze immuun, waardoor ze controle over de rig voor 10 sec, en het kloppen van Back nabijgelegen vijanden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474592] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nPacifist Rig\n[q]Tijdens het gevecht wordt een piloot aangewezen meer dan 8 sec voordat het luchtdruppelen van de Pacifist Rig MK-3 op hun locatie, waardoor ze immuun, waardoor ze controle over de rig voor 10 sec, en het slaan van Back nabijgelegen vijanden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474593] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nPacifist Rig\n[q]Tijdens het gevecht is een piloot aangewezen meer dan 8 sec voordat het luchtdruppelen van de Pacifist Rig MK-4 op hun locatie, waardoor ze immuun, waardoor ze controle over het platform voor 10 sec, en het kloppen van Back nabijgelegen vijanden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474594] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nOverdrive Pylon\n[q]Na 30 sec van de strijd, partyleden en Brann dealen 10 % meer schade en genezing voor 30 sec. Kan maar één keer per gevecht voorkomen.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474595] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nOverdrive Pylon\n[q]Na 30 sec van het gevecht, delen partijleden en Brann 15 % meer schade en genezing gedurende 30 sec. Kan maar één keer per gevecht voorkomen.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474596] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nOverdrive Pylon\n[q]Na 30 sec van de strijd, partijleden en Brann dealen 20 % meer schade en genezing voor 40 sec. Kan maar één keer per gevecht voorkomen.\n\nJe hebt deze curio al in je collectie."}
