MultiLanguageSpellData['nl'][474599] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nMechasaur EZ-bouwkit\n[q]Brann's Epic Egg herbergt nu 1 mechasaurs die vijanden voor (4000 / 1000) sec terwijl in het ei.\n\nMechasaurs zal periodiek stampen in aanvulling op hun gebruikelijke capaciteiten, de handel matig Brandschade verdeeld tussen nabijgelegen vijanden. Getroffen vijanden ontploffen na 5 sec. Met matige brandschade.\n\nBrann's epische ei\nBrann roept een duivelsaurus ei op. Hopelijk komt het uit.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474600] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nAutomatische voetbomdispenser\n[q]Brann's spreuken en vermogens hebben de kans om 2 voetbommen te laten vallen op het veld gedurende 10 sec.\n\nRennen in een voetbom schopt het op uw vijand doel dealen aanzienlijke brand schade aan alle vijanden in een straal van 6 yards.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474601] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nImpact Conversie Matrix\nBrann activeert de conversiematrix voor 10 sec. Een klein percentage van alle partijschade behandeld gedurende deze tijd wordt omgezet in primaire status en splitsen tussen partij leden.\n\nNa de conversie matrix bevoegdheden naar beneden, de primaire status buff blijft gedurende 10 sec. Dit effect kan niet meer dan eenmaal per 2 minuten optreden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474602] = {name = "Blastburn Roarcannon", additional_info = "60 yd bereik\nDirect\n[q]Flarendo volgt een doelwit tijdens het opladen, dan sluit op zijn plaats en bereidt zich voor om te vuren. Eenmaal klaar, vuurt het een straal over de volgende 3 seconden. De straal brengt 66606435 Brand elke 0.1 sec schade aan spelers op contact, vernietigend hen."}
