MultiLanguageSpellData['nl'][474605] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nPocketfabriek\n[q]Brann's spreuken en vaardigheden hebben een kans om de Pocket Factory opdracht te geven om 1 toren te bouwen om te helpen voor 10 sec.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474606] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nGoblomagnetische bounzing grenade\n[q]Brann heeft een kans tijdens de strijd om een GMB granaat te gooien op een vijandelijke doel omgaan met matige Natuurschade met een 20% kans om te verdoven voor 1,5 sec. Dit heeft een kans van 25% om een nieuw doel te bereiken.\n\nDe granaat kan veilig op partijleden stuiteren.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474607] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nPinged Augment Chip\nDe maximale gezondheid van [q]Brann wordt verhoogd met 4 procent en zijn schade en genezing wordt verhoogd met 20 procent.\n\nTijdens het gevecht, Brann kan worden het doelwit door mechanische bots die fixeren op hem die kan worden vernietigd of verdoofd. Als ze Brann bereiken, zal hij 30 procent van zijn maximale gezondheid aan schade lijden en gedurende 5 seconden verdoofd zijn.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474608] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nReverse Engineered Goblin Death Bomb\n[q]Wanneer de gezondheid van een speler tijdens het gevecht onder de 50% daalt, gooit Brann een gigantische bom die ontploft bij impact.\n\nDe explosie klopt Back en vertraagt de omringende vijanden met 45% voor 5 sec en geneest nabijgelegen partijleden voor 35% van hun maximale gezondheid. Kan alleen elke 1,5 min. voorkomen.\n\nJe hebt deze curio al in je collectie."}
