MultiLanguageSpellData['nl'][1214642] = {name = "Grotere Badder Bomb Blast", additional_info = "Onbeperkt bereik\nDirect\n[q]Galywix omhult zijn primaire doel met vele explosieven veroorzaken 100 Fysieke schade en verhoogt Grotere Badder Bomb Blast schade genomen door 200 % voor 1,2 min. Dit effect stapelt zich en kan niet worden ontlopen of gepacht.\n\nBovendien veroorzaakt 100 Brand schade aan spelers binnen 30 meter van het primaire doel, het toepassen van Blast Burns. Deze munitie (meestal) ontploffen bij inslag.\n\nEchter, een deel van de fuze binnen de bos verspreidt zich over de arena."}
