MultiLanguageSpellData['nl'][1215953] = {name = "Statische lading", additional_info = "300 yd bereik\n3 sec gegoten\n[q]Mug'Zee maakt gebruik van elektriciteit om hem heen en laadt 6708070 Fysieke schade aan spelers op zijn pad, vernietigen alle Earthshaker Gaol s en Unstable Crawler Mijnen.\n\nBij het bereiken van zijn doel, Mug'Zee ontketent een Bulletstorm."}
MultiLanguageSpellData['nl'][1215957] = {name = "Tremor Klauw", additional_info = "100 yd bereik\n2,5 sec gegoten\n[q]Knocks alle vijanden binnen 100 meter van de caster Back.\nVermindert de beweging Speed van alle vijanden binnen 60 yards met 40% voor 3 sec.\nVeroorzaakt 243973 fysieke schade aan vijanden binnen 60 meter."}
