MultiLanguageSpellData['nl'][1217083] = {name = "Voetblasters", additional_info = "300 yd bereik\nDirect\n[q]Lockenstock lanceert verschillende landmijnen in de kamer. Stappen op een Foot-Blaster activeert een Instabiele Explosie en insluit Instabiele Shrapnel in de triggering speler. Bovendien, deze reactieve mijnen ontploffen bij contact met andere uitvindingen of Wire Transfer, waardoor een Onstabiele Explosie."}
