MultiLanguageSpellData['nl'][1217095] = {name = "Tranquilizer-dart", additional_info = "40 yd bereik\nDirect\n[q]Schiet een Tranquilizer Dart op je doel, waardoor ze vallen in een diepe en zalige sluimer."}
MultiLanguageSpellData['nl'][1217096] = {name = "Etherische bescherming", additional_info = "Direct\nOngeveer 2 procs per minuut\n[q]Uw spreuken en vermogens hebben een hoge kans om de energie om u heen samen te voegen, waardoor u een Shield krijgt die de schade vermindert van 20% tot 2668 totale schade.\n\nBij een daling van minder dan 40% gezondheid, krijgen dit effect bij 500% effectiviteit. Dit effect kan slechts eenmaal per 6 minuten optreden.\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1217101] = {name = "Etherische Reaping", additional_info = "Direct\nOngeveer 2 procs per minuut\n[q]Uw schadelijke spreuken en vermogens hebben de kans om latente energieën om u heen te richten om 1334 Arcane schade te veroorzaken verdeeld tussen uw doelwit en nabijgelegen vijanden. Vijanden onder de 35% gezondheid krijgen 20% extra schade.\n(100ms afkoeling)"}
