MultiLanguageSpellData['nl'][1218301] = {name = "Prototype Auto-Advertiser", additional_info = "8 yd bereik\n{Instant} {5 min cooldown}\n[q]Plaats de auto-adverteerders, waardoor alle nabijgelegen wezens extreem geïrriteerd raken en 50% verhoogde schade aan u toebrengen gedurende 3 minuten.\n\nAlleen bruikbaar in Undermine. Vijanden laten extra marktonderzoek voor de caster vallen terwijl ze actief zijn."}
