MultiLanguageSpellData['nl'][1218305] = {name = "Gesmolten hengst", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Gesmeed zoals hun schoenen ooit waren, zijn deze beesten nu minder paarden en lege energie in hun gelijkenis.\"\nDrop:\nGebied:\nZicht op Stormwind (herzien)"}
MultiLanguageSpellData['nl'][1218306] = {name = "Void-Scarred Pack Moeder", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Vechtend tegen haar corrupte begeleiders bevrijdde deze moeder zichzelf en haar pups. Vrijheid van hun verzorgers bevrijdde hen echter niet van de leegte in deze verloren plek. Ze leerde haar pups om nog gevaarlijker beesten te zijn, en ze stalken nu overal in Orgrimmar om haar voedsel te halen omdat ze allemaal strijden om te overleven.\"\nDrop:\nGebied:\nZicht op Orgrimmar (herzien)"}
MultiLanguageSpellData['nl'][1218307] = {name = "Void-Scarred Windrider", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Toen de lege energieën werden losgelaten, dreef het de meeste windrijders wild. Ze hebben elkaar en hun trainers vermoord. De poorten naar hun haan werden op slot gedaan door de overlevenden. Sommige overlevende windrijders zijn nog steeds te zien glijden boven, maar niemand durft terug te keren naar hun nieuwe dodelijke domein om te zien wat er overblijft.\"\nDrop:\nGebied:\nZicht op Orgrimmar (herzien)"}
MultiLanguageSpellData['nl'][1218308] = {name = "Aanmaak Inferno", additional_info = "Direct\n[q]Blazikon ontketent een vurige uitbarsting naar elke gedoofde kaars, reanimerend die kaars en het toebrengen van 8487876 Brandschade aan alle spelers op zijn pad.\n\nDe inferno sears alle spelers, veroorzaken 242445 Brand schade elke 1 sec voor 8 sec. Dit effect stapelt zich op."}
