MultiLanguageSpellData['nl'][1218314] = {name = "Ny'alothan Schaduwworm", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat je Ny'alothan Shadow Worm.\n[q]\"Een overblijfsel van het verleden van het Zwarte Rijk, deze voorlopers van de Abyss wormen zijn opnieuw aan het herleven met de opkomst van Ny'alotha.\"\nResultaten:\nDe VisionsCategory beheersen:\nVisions of N'Zoth Revisited"}
MultiLanguageSpellData['nl'][1218316] = {name = "Corruptie van de aspecten", additional_info = "1.5 sec gegoten\n[q]Summons en verwerpt de Corruptie van de Aspecten. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"Met N'Zoth's triomf komt wat begon met Galakrond tot bloei. Nu de Aspecten weg zijn, is de corruptie van hun soort compleet.\"\nVerkoper:\nTorie\nGebied:\nDornogal\nKosten:\n40000"}
MultiLanguageSpellData['nl'][1218317] = {name = "Void-Crystal Panther", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat een rijbare Void-Crystal Panther.\n[q]\"Hoewel vele kostbare edelstenen zijn beschadigd door lege energieën in gruwelijke visioenen, kunnen Meester Jewelcrafters ze nog steeds gebruiken om machtige panterpaarden te maken.\"\nBeroep:\nJuwelieren"}
