MultiLanguageSpellData['nl'][1221061] = {name = "Xal'atath's Gift", additional_info = "100 yd bereik\nDirect\n[q]De Leegte Afgezant werpt een duister gebed. Wanneer de cast voltooid, nabijgelegen wezens krijgen Xal'atath's Gift, het verhogen van hun schade gedaan met tot 50% en het verminderen van hun schade genomen met maximaal 100% voor 20 sec gebaseerd op de hoeveelheid van de Leegte Afgezant's Shield die blijft.\n\nVerslaan van de Leegte Afgezant stelt spelers, waardoor ze 20% Versatility en 30% spreuk en de mogelijkheid afkoelen tarief voor 30 sec sec."}
MultiLanguageSpellData['nl'][1221063] = {name = "Xal'atath's Gift", additional_info = "Direct\n[q]Xal'atath regent bollen van kosmische energie die proberen om nabijgelegen schepselen Xal'atath's Gift te verlenen, waardoor hun schade wordt verhoogd met 5% en hun schade wordt verminderd met 10% voor 20 sec. Dit effect stapelt zich op.\n\nAls spelers deze bollen verstoren claimen ze zelf de kracht om hun Haste en Beweging Speed gedurende 30 sec met 2% te verhogen. Dit effect stapelt zich op."}
