MultiLanguageSpellData['nl'][1222232] = {name = "Devorer's Ire", additional_info = "Onbeperkt bereik\nDirect\n[q]Adarus stort bollen ravende leegte op verschillende locaties, waardoor 5621532 Kosmische schade aan alle spelers, indien niet onderschept.\n\nAdarus richt zijn blik op spelers die deze bollen onderschepten, hen voortdurend aanvallen met Consume en hun fysieke schade verhogen met 100%.\n\nBij verwijdering, Devorer's Ire transfers naar een nabijgelegen speler en brengt 2108075 Kosmische schade aan alle spelers."}
MultiLanguageSpellData['nl'][1222234] = {name = "Vantus Rune: Ondermijning", additional_info = "Onbeperkt bereik\n1.5 sec gegoten\n[q]Eens per week, jezelf aanpassen aan de energieën van de gerichte Undermine inval baas en krijg de volgende aura:\n\nVantus Rune: Bevrijding van Ondermijning\nVerhoog uw Versatility met 1500 bij het bestrijden van de gerichte inval baas. Dit effect duurt de hele week."}
MultiLanguageSpellData['nl'][1222239] = {name = "Vantus Rune: Ondermijning", additional_info = "Onbeperkt bereik\n1.5 sec gegoten\n[q]Eens per week, jezelf aanpassen aan de energieën van de gerichte Undermine inval baas en krijg de volgende aura:\n\nVantus Rune: Bevrijding van Ondermijning\nVerhoog je Versatility met 1700 bij het bestrijden van de gerichte inval baas. Dit effect duurt de hele week."}
