MultiLanguageSpellData['nl'][1222271] = {name = "Wyvern's Cry", additional_info = "Direct\n[q]Terwijl in de strijd, elke 30 seconden uw volgende Kill Command roept de hulp van een Beest.\n\nWyvern\nEen Wyvern daalt af van de hemel en laat een strijdkreet los die de schade van jou en je huisdieren met 10% verhoogt gedurende 15 sec.\n\nZwijn\nEen Boar laadt 3 keer via uw doel, dealen (400% van Attack Power) fysieke schade aan het primaire doel en (160% van Attack Power) schade tot 8 nabijgelegen vijanden.\n\nBeer\nEen Beer springt in de strijd, het vlees van je vijanden herstellend, dealend (400% van Attack Power) schade over 10 sec tot 8 nabijgelegen vijanden."}
