MultiLanguageSpellData['nl'][1224765] = {name = "Arcane stromingen", additional_info = "Onbeperkt bereik\nDirect\n[q]Vluchten van blootgestelde energie slaan op de grond, 70 Arcane schade toebrengen aan spelers binnen 5 meter van impact."}
MultiLanguageSpellData['nl'][1224766] = {name = "Webspreiders", additional_info = "Direct\n[q]Webspreiders zijn omgeven door webs. Staan in webs vermindert beweging Speed en periodiek paait hinderlaag. Val de Web Spreaders aan om de riem tijdelijk in te trekken."}
MultiLanguageSpellData['nl'][1224767] = {name = "King's Thrall", additional_info = "Onbeperkt bereik\nDirect\n[q]Een speler bezwijkt aan hun eed, steeds mind-controlled voor 12 sec. De leegte versterkt de speler en geneest ze tot volle gezondheid.\n\nNa afloop ontploft Thrall met 100 schaduwschade aan alle spelers."}
MultiLanguageSpellData['nl'][1224775] = {name = "Necklace of the Devout", additional_info = "[q]Je bent een van de vromen. Verhoogt de effectiviteit van de Heilige Vlam Ward met 100%.\n\nHeilige Vlam's Ward:\nTerwijl in Khaz Algar, het omgaan van schade heeft een grote kans op het verbranden van de vijand met rechtvaardig vuur omgaan 2 Radiant schade. Bovendien neem je 5% minder schade aan."}
MultiLanguageSpellData['nl'][1224776] = {name = "Subjugatieregel", additional_info = "Onbeperkt bereik\nDirect\n[q]Salhadaar voert een combinatie van stakingen uit om spelers te onderwerpen."}
MultiLanguageSpellData['nl'][1224785] = {name = "Instortende ster", additional_info = "Onbeperkt bereik\nDirect\n[q]Adarus werpt een instortende bol Kosmische energie op de speler die momenteel wordt gebrandmerkt door Discord's Ire, waardoor 40 Kosmische schade aan alle spelers wordt toegebracht.\n\nDe impact laat een groot gebied van Encroaching Oblivion achter."}
MultiLanguageSpellData['nl'][1224787] = {name = "Veroveren", additional_info = "Onbeperkt bereik\n4 sec gegoten\n[q]Salhadaar verplettert zijn huidige doelwit, veroorzaakt 101187582 Fysieke schade en een extra 75890687 Schaduwschade verdeeld over alle spelers binnen 8 yards, waardoor ze omhoog.\n\nSpelers sloeg verliezen een stapel van Oath-Bound. Verhoogt de schade van Conquer met 500% voor 20 sec."}
