MultiLanguageSpellData['nl'][1224978] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nHatarang\n[q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 1 debuff(s) toe te passen op 2 doelen.\n\nMogelijke debuffs zijn een 20 % toename van de schade, 20 % vermindering van de schade, en 20 % aanval en gegoten Speed daling.\n\nJe hebt deze curio al in je collectie."}
