MultiLanguageSpellData['nl'][1225061] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nZand van K'aresj\n[q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, begint zand te draaien rond partijleden, het verlenen van 6 % Critical Strike tot 10 keer en vertragen van nabijgelegen vijanden door 6 %.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225062] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nZand van K'aresj\n[q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, begint zand te draaien rond partijleden, waardoor 8 % Critical Strike tot 10 keer en vertragen van nabijgelegen vijanden door 8 %.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225063] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nZand van K'aresj\n[q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, begint zand te draaien rond partijleden, het verlenen van 10 % Critical Strike tot 10 keer en het vertragen van nabijgelegen vijanden door 10 %.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225064] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nZand van K'aresj\n[q]Wanneer Brann Gathering Tools gebruikt, begint het zand rond partijleden te draaien, waarbij 12 % Critical Strike tot 10 keer wordt toegekend en de nabijgelegen vijanden met 12 % worden vertraagd.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225065] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nTemporal Decelerator Crystal\n[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en het werpen van Speed met 20 % gedurende 30 sec. Het doden van de doel Elite terwijl het debuff is actief verleent de partij een 2 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225066] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nTemporal Decelerator Crystal\n[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite wordt verminderd en Speed met 30 % wordt gegoten gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 4 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225067] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nTemporal Decelerator Crystal\n[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en het werpen van Speed met 40 % gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 6 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225068] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nTemporal Decelerator Crystal\n[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de aanval van de Elite wordt verminderd en Speed gedurende 30 sec met 50 % wordt gegoten. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 8 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225069] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nBatterij Aegis\n[q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 3 procent verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 5 procent van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 1 procent vermindering van de schade en 2 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 1 % stapelen tot 3 keer.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225070] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nBatterij Aegis\n[q]Terwijl de Aegis is uitgerust, delen alle partijleden 6 procent meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 10 procent van de schade die je hebt opgelopen in die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen 2 procent vermindering van de schade en 3 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 2 % stapelen tot 3 keer.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225072] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nBatterij Aegis\n[q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 9% meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 15% van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 3% vermindering van de schade en 4% verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 3% stapelen tot 3 keer.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225073] = {name = "Optellen", additional_info = "1.5 sec gegoten\nReagentia:\nBatterij Aegis\n[q]Terwijl de Aegis is uitgerust, delen alle partijleden 12 procent meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 20 procent van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 4 procent schadevermindering en 5 procent verhoogde genezing ontvangen na revival, maar vermindert hun schade en genezing behandeld met 4 % stapelen tot 3 keer.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225074] = {name = "Kleine Rune van Twilight Verwoesting", additional_info = "3,5 sec gegoten\nVereist Armor\n[q]Voer Kleinere Rune van Twilight Devastation toe aan een roer.\n\nHiermee kunt u uw aanvallen hebben een kans om een straal van Twilight Devastation te activeren, dealen tot (1 * 845195 * 3) Schaduwschade aan vijanden voor u.\n\nKan niet worden toegepast op items onder niveau 350. Dit effect is vluchtig en zal alleen werken tijdens The War Within Season 2."}
