MultiLanguageSpellData['nl'][1226511] = {name = "Oogstvogel", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De lente oogsthog is op zijn meest energieke in de vroege ochtend. Het zal het grootste deel van de dag snuiven voor voedsel of bellowing oproepen voor andere oogsthogs.\"\nHandelspost"}
