MultiLanguageSpellData['nl'][1226531] = {name = "Summer Harvesthog", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Het Zomer Harvesthog ligt graag in de zon of gaat zwemmen in een helder meer. Ze zijn uitstekend in het foerageren naar voedsel, maar ze moeten erin gesjouwd worden.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1226532] = {name = "Winter Oogstvogel", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Winter Harvesthogs zijn voornamelijk nachtelijke wezens. Ze zijn iets langzamer dan andere oogsthogs, maar hun uithoudingsvermogen is ongeëvenaard.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1226533] = {name = "Autumn Harvesthog", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Autumn Harvesthogs blinken uit in snuffling voor voedsel in de koelere maanden. Hun scherpe reukzin maakt hen uitstekende metgezellen voor een forrest foerage, maar moeilijk te controleren in aromatische settings.\"\nHandelspost"}
