MultiLanguageSpellData['nl'][1227206] = {name = "Grotere Rune van oneindige sterren", additional_info = "3,5 sec gegoten\nVereist Armor\n[q]Grotere Rune van Oneindige Sterren toepassen op een roer.\n\nUw spreuken en vermogens hebben de kans om een nabije vijand te slaan met een Oneindige Ster, omgaan (1 * 362226) Arcane schade en het verhogen van hun schade uit uw Oneindige Sterren door (1 * 126779), stapelen tot 6 keer voor het resetten.\n\nKan niet worden toegepast op items onder niveau 350. Dit effect is vluchtig en zal alleen werken tijdens The War Within Season 2."}
