MultiLanguageSpellData['nl'][1227275] = {name = "Opgeladen Shield", additional_info = "100 yd bereik\nDirect\n[q]Strakt het primaire doel met een geëlektrificeerde Shield, elektriciteit blaast het doel in het toebrengen van 9697798 Natuurschade en het verminderen van hun beweging Speed met 60% voor 8 sec.\n\nVolgende aanvallen sturen ketens van bliksem veroorzaken 2424449 Natuurschade tot maximaal 5 doelen."}
MultiLanguageSpellData['nl'][1227276] = {name = "Soulfray Annihilation", additional_info = "300 yd bereik\nDirect\n[q]De Soulbinder Naazindhri ontketent een bol in de richting van willekeurig gerichte spelers, waardoor 11250162 Arcane schade toebrengt aan elke speler getroffen door de bol en waardoor ze 15% verhoogde schade gedurende 20 sec.\n\nIndien een Bindkamer door de bol wordt geraakt, wordt zijn Shield vernietigd en neemt de Niet-geconsolideerde Ziel 200% meer schade op."}
