MultiLanguageSpellData['nl'][1229185] = {name = "Etherische energieomvormer", additional_info = "[q]Wanneer een partijlid minder dan 60% gezondheid, een Ethereal Energy Converter materialiseert, dealen matig schade aan nabijgelegen vijanden en treiteren hen voor 4 sec. Zodra de treunt verloopt, de Converter releases een Etherwave genezing nabij bondgenoten voor 20% van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 2 sec."}
MultiLanguageSpellData['nl'][1229186] = {name = "Etherische energieomvormer", additional_info = "[q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, dealen matige schade aan nabijgelegen vijanden en treiteren hen voor 4 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 30 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 4 sec."}
MultiLanguageSpellData['nl'][1229187] = {name = "Etherische energieomvormer", additional_info = "[q]Wanneer een partijlid minder dan 60 procent gezondheid daalt, materialiseert een Ethereal Energy Converter, dealt matige schade aan nabijgelegen vijanden en treitert hen voor 6 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 40 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 6 sec."}
MultiLanguageSpellData['nl'][1229188] = {name = "Etherische energieomvormer", additional_info = "[q]Wanneer een partijlid minder dan 60 procent gezondheid daalt, materialiseert een Ethereal Energy Converter, dealt matige schade aan nabijgelegen vijanden en treitert hen voor 6 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 50 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 8 sec."}
MultiLanguageSpellData['nl'][1229189] = {name = "Mana-tinted bril", additional_info = "[q]Brann dons mana-tinted bril tijdens het gevecht, periodiek verhogen van zijn schade gedaan met 4 % en schade genomen met 5 % elke 5 sec tot 10 keer.\n\nHet versturen van de bril zal Brann genezen voor 25 procent van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 2 sec.\nAnders wordt dit effect automatisch verwijderd wanneer Brann daalt onder 30 procent gezondheid die voorkomt dat de verdoving optreedt."}
MultiLanguageSpellData['nl'][1229190] = {name = "Mana-tinted bril", additional_info = "[q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 4% en schade genomen met 5% om de 5 sec tot 10 keer.\n\nHet versturen van de bril zal Brann genezen voor 40% van zijn maximale gezondheid en verdoving nabijgelegen vijanden voor 3 sec.\nAnders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt."}
MultiLanguageSpellData['nl'][1229191] = {name = "Mana-tinted bril", additional_info = "[q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 5% en schade genomen met 5% om de 5 sec tot 10 keer.\n\nHet versturen van de bril zal Brann genezen voor 55% van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 4 sec.\nAnders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt."}
MultiLanguageSpellData['nl'][1229192] = {name = "Mana-tinted bril", additional_info = "[q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 5% en schade genomen met 5% om de 5 sec tot 10 keer.\n\nHet verkopen van de bril zal Brann genezen voor 70% van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 5 sec.\nAnders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt."}
