MultiLanguageSpellData['nl'][1229197] = {name = "Hatarang", additional_info = "[q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 1 debuff(s) toe te passen op 2 doelen.\n\nMogelijke debuffs zijn een 20% toename van de schade, 20% vermindering van de schade, en 20% aanval en gegoten Speed daling."}
MultiLanguageSpellData['nl'][1229198] = {name = "Hatarang", additional_info = "[q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 1 debuff(s) toe te passen op 3 doelen.\n\nMogelijke debuffs zijn een 25 % schade genomen toename, 25 % schade gedeeld daling, en 25 % aanval en gegoten Speed daling."}
MultiLanguageSpellData['nl'][1229199] = {name = "Hatarang", additional_info = "[q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 2 debuff(s) toe te passen op 4 doelen.\n\nMogelijke debufs zijn een 30 % schade genomen toename, 30 % schade gedeeld daling, en 30 % aanval en gegoten Speed daling."}
MultiLanguageSpellData['nl'][1229200] = {name = "Hatarang", additional_info = "[q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 2 debuff(s) toe te passen op 5 doelen.\n\nMogelijke debuffs zijn een 35 % schade genomen toename, 35 % schade gedeeld daling, en 35 % aanval en gegoten Speed daling."}
MultiLanguageSpellData['nl'][1229201] = {name = "Nether Overlay Matrix", additional_info = "[q]Tijdens het gevecht heeft Brann de kans om een 90 % zwakkere etherische kopie van zichzelf te manifesteren om 1 min aan uw zijde te vechten."}
MultiLanguageSpellData['nl'][1229202] = {name = "Nether Overlay Matrix", additional_info = "[q]Tijdens het gevecht heeft Brann de kans om een 80% zwakkere etherische kopie van zichzelf te manifesteren om 1 min aan uw zijde te vechten."}
MultiLanguageSpellData['nl'][1229203] = {name = "Nether Overlay Matrix", additional_info = "[q]Tijdens de strijd heeft Brann de kans om een 70% zwakkere etherische kopie van zichzelf te manifesteren om 1 min aan uw zijde te vechten."}
MultiLanguageSpellData['nl'][1229204] = {name = "Nether Overlay Matrix", additional_info = "[q]Tijdens de strijd heeft Brann de kans om een 60% zwakkere etherische kopie van zichzelf te manifesteren om 1 min aan uw zijde te vechten."}
MultiLanguageSpellData['nl'][1229205] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, waardoor 6% Critical Strike tot 10 keer en vertragen nabijgelegen vijanden 6%.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1229206] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, begint zand te draaien rond partijleden, waardoor 8 % Critical Strike tot 10 keer en vertragen van nabijgelegen vijanden door 8 %.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1229207] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, begint zand te draaien rond partijleden, het verlenen van 10 % Critical Strike tot 10 keer en het vertragen van nabijgelegen vijanden door 10 %.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1229208] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint het zand rond partijleden te draaien, waarbij 12 % Critical Strike tot 10 keer wordt toegekend en de nabijgelegen vijanden met 12 % worden vertraagd.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1229209] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80% of hoger en op 20% of lager gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en gegoten Speed met 20% gedurende 30 sec. Het doden van de doel Elite terwijl de debuff actief is verleent de partij een 2% stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229210] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite wordt verminderd en Speed met 30 % wordt gegoten gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 4 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229211] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en het werpen van Speed met 40 % gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 6 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229212] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de aanval van de Elite wordt verminderd en Speed gedurende 30 sec met 50 % wordt gegoten. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 8 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229213] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 3 procent verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 5 procent van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 1 procent vermindering van de schade en 2 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 1 % stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229214] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, delen alle partijleden 6 procent meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 10 procent van de schade die je hebt opgelopen in die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen 2 procent vermindering van de schade en 3 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 2 % stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229215] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 9% meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 15% van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 3% vermindering van de schade en 4% verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 3% stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229216] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, delen alle partijleden 12 procent meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 20 procent van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 4 procent schadevermindering en 5 procent verhoogde genezing ontvangen na revival, maar vermindert hun schade en genezing behandeld met 4 % stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229217] = {name = "Audio Amplification Crystal", additional_info = "[q]Brann's stem is licht versterkt met Arcane magie waardoor zijn woorden de partij mogelijk een buff geven gebaseerd op wat werd gesproken."}
