MultiLanguageSpellData['nl'][1233516] = {name = "K'arroc Swiftwing", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Een geschenk voor verleende diensten, deze K'arroc heeft zijn aandeel van gevaarlijke vluchten gezien.\"\nZoekopdracht:\nOp naar Tazavesh, Opnieuw\nGebied:\nK'aresj"}
MultiLanguageSpellData['nl'][1233518] = {name = "Lavendel K'arroc", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De vorige meester van K'arroc stierf tijdens het onderzoek naar Untethered Space. Misschien accepteert het je in plaats daarvan... of misschien niet.\"\nVerkoper:\nShad'ani's\nGebied:\nK'aresj\nKosten:\n10"}
