MultiLanguageSpellData['nl'][1233539] = {name = "Snijden", additional_info = "2 sec gegoten\n[q]Op het bereiken van 100 energie Dimensius verhoogt zijn dichtheid, het creëren van een krachtige innerlijke kracht die maakt 1686460 Schaduw schade elke 1 voor 5 sec en trekt in spelers, Voidstars, Black Holes, en de Accretion Disk.\n\nNa 5 sec elke speler buiten een Voidstar's Gravity Well wordt onmiddellijk getrokken in Dimensius en verzonden naar Oblivion."}
MultiLanguageSpellData['nl'][1233542] = {name = "De botvriezer", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Bitter rivaal van The Bone Melter, deze kruiper werd verdreven uit hun hol in de buurt van Manaforge Omega na een verpletterende nederlaag. Het probeert nu te leren van degene die zijn grootste vijand onttroond heeft.\"\nManaforge Vandalen\nHerinnering:\n14\nLocatie:\nSchaduwpunt"}
MultiLanguageSpellData['nl'][1233544] = {name = "Summon Storytime Rug", additional_info = nil}
MultiLanguageSpellData['nl'][1233546] = {name = "Ruby Void Creeper", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Rescued\" door de K'aresh Trust voor studie, deze leegte kruiper is gebleken te zijn een ongelooflijk stevige berg.\nVerkoper:\nOm'sirik\nGebied:\nK'aresj\nKosten:\n8125"}
MultiLanguageSpellData['nl'][1233547] = {name = "Acid Void Creeper", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Deze kruiper heeft zich opgegeten aan schadelijke dampen waardoor zijn lichaam wordt doordrenkt met krachtige zuren.\"\nVerkoper:\nShad'ani's\nGebied:\nK'aresj\nKosten:\n7"}
