MultiLanguageSpellData['nl'][1233553] = {name = "Onbewerkstellig Nederlandprim", additional_info = "[q]Uw schadelijke vermogens trekken gefocust leegte door het prisma om te handelen ( 441 * 1 ) Kosmische schade verdeeld tussen uw doel en nabijgelegen vijanden. De schade steeg met 30% per vijand, tot 150%. Dit effect kan elke 10 sec optreden en accumuleert Latente Kracht binnen het prisma, tot 18 keer.\n(10s afkoeling)"}
