MultiLanguageSpellData['nl'][1233559] = {name = "Blauwe Barry", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Een bijzonder zeldzame variant van leiBack, \"Blue Barry\" werd eerder gebruikt als een beest van last.\"\nZoekopdracht:\nEen blauw voor jou\nGebied:\nK'aresj"}
MultiLanguageSpellData['nl'][1233561] = {name = "Nieuwsgierig SlateBack", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Deze nieuwsgierige leiBack slaagde erin om zichzelf vast te zitten in een doos. Hoe het binnenin past is nog steeds in de lucht.\"\nDrop:\nWriggling Pinnacle Cache\nGebied:\nK'aresj"}
