MultiLanguageSpellData['nl'][1233659] = {name = "Hatarang", additional_info = "100 yd bereik\nDirect\nOngeveer 2 procs per minuut\n[q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 1 debuff(s) toe te passen op 3 doelen.\n\nMogelijke debuffs zijn een 25% toename van de schade, 25% vermindering van de schade, en 25% aanval en gegoten Speed daling.\n(20s afkoeling)"}
