MultiLanguageSpellData['nl'][1233693] = {name = "Zand van K'aresj", additional_info = "Onbeperkt bereik\nDirect\n[q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, waardoor 8% Critical Strike tot 10 keer en het vertragen van nabijgelegen vijanden door 8%.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1233694] = {name = "Zand van K'aresj", additional_info = "Onbeperkt bereik\nDirect\n[q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, het verlenen van 10% Critical Strike tot 10 keer en vertragen van nabijgelegen vijanden met 10%.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1233695] = {name = "Zand van K'aresj", additional_info = "Onbeperkt bereik\nDirect\n[q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, waardoor 12% Critical Strike tot 10 keer en vertragen nabijgelegen vijanden met 12%.\n\nDealen van een Critical Strike creëert een zandduivel op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, Leather's en schatten te vinden."}
MultiLanguageSpellData['nl'][1233699] = {name = "Ethernova", additional_info = "100 yd bereik\nDirect\n[q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, dealen matige schade aan nabijgelegen vijanden en treiteren hen voor 4 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 30 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 4 sec."}
MultiLanguageSpellData['nl'][1233700] = {name = "Ethernova", additional_info = "100 yd bereik\nDirect\n[q]Wanneer een partijlid minder dan 60 procent gezondheid daalt, materialiseert een Ethereal Energy Converter, dealt matige schade aan nabijgelegen vijanden en treitert hen voor 6 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 40 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 6 sec."}
MultiLanguageSpellData['nl'][1233701] = {name = "Ethernova", additional_info = "100 yd bereik\nDirect\n[q]Wanneer een partijlid minder dan 60 procent gezondheid daalt, materialiseert een Ethereal Energy Converter, dealt matige schade aan nabijgelegen vijanden en treitert hen voor 6 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 50 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 8 sec."}
MultiLanguageSpellData['nl'][1233702] = {name = "Vanquish", additional_info = "Onbeperkt bereik\nDirect\n[q]Salhadaar legt zijn huidige doelwit vast, veroorzaakt 22486129 Fysieke schade en een extra 35415654 Schaduwschade aan alle spelers voor hem, waardoor ze worden weggeslagen.\n\nVerhoogt de schade van Vanquish met 500% voor 20 sec."}
