MultiLanguageSpellData['nl'][1233775] = {name = "Naran's Everdisc", additional_info = "40 yd bereik\n{Instant} {1 min cooldown}\n[q]Bekwaamheid voor artefact\n\nGooi een schijf van arcane energie die naar buiten boog voordat hij naar je terugkeert.\n\nNaran's Everdisc brengt [(1930% Attack/Spell Power)] Arcane schade toe aan vijanden op zijn pad.\n\nOnderbreek het terugkerende projectiel om het opnieuw te gooien, tot 5 extra keer, toenemende schade met 60% voor elke volgende worp."}
