MultiLanguageSpellData['nl'][1233894] = {name = "Achterwindconduit", additional_info = "Onbeperkt bereik\nDirect\n[q]Genereert een uitbarsting van Speed bij het verlaten van het gevecht, het verhogen van uw Beweging Speed met 60% voor 10 sec verval in de tijd. Met behulp van een defensieve afkoeling terwijl in de strijd heeft windstoten om je heen, het toepassen van een Shield voor 8 sec gelijk aan 30% van uw ontbrekende gezondheid.\n(30s afkoeling)"}
MultiLanguageSpellData['nl'][1233895] = {name = "Audio Amplification Crystal", additional_info = "Onbeperkt bereik\nDirect\n[q]Brann's stem wordt matig versterkt met Arcane magie waardoor zijn woorden de partij mogelijk een buff geven gebaseerd op wat werd gesproken."}
MultiLanguageSpellData['nl'][1233896] = {name = "Batterij Aegis", additional_info = "Onbeperkt bereik\nDirect\n[q]Terwijl de Aegis is uitgerust, handelen alle partijleden 6% meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 10% van de schade die je in die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 2% schadevermindering en 3% verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 2% stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1233897] = {name = "Temporal Decelerator Crystal", additional_info = "Onbeperkt bereik\nDirect\n[q]Het beschadigen van een Elite op 80% of hoger en op 20% of lager gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de aanval van de Elite wordt verminderd en Speed gedurende 30 sec met 30% wordt gegoten. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 4% stapelen Haste buff."}
MultiLanguageSpellData['nl'][1233898] = {name = "Quizzisch apparaat", additional_info = "Onbeperkt bereik\nDirect\nOngeveer 2 procs per minuut\n[q]Brann heeft de kans om spelers een bonus van 10% voor gezondheid, schade, of genezing voor 20 sec op basis van zijn geselecteerde Combat Role.\n\nSpelers hebben de kans om Brann een bonus van 10% te geven aan gezondheid, schade of genezing voor 20 sec. gebaseerd op hun geselecteerde rol.\n(20s afkoeling)"}
MultiLanguageSpellData['nl'][1233899] = {name = "Etherische energieomvormer", additional_info = "Onbeperkt bereik\nDirect\n[q]Wanneer een partijlid minder dan 60% gezondheid, een Ethereal Energy Converter materialiseert, dealen matig schade aan nabijgelegen vijanden en treiteren hen voor 4 sec. Zodra de treunt verloopt, de Converter releases een Etherwave genezing nabij bondgenoten voor 30% van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 4 sec."}
