MultiLanguageSpellData['nl'][1234372] = {name = "Stormchirurg", additional_info = "[q]Grants 3 extra rangen van Storm Chirurgie.\n\nStormchirurg\nJe mag bewegen tijdens het gieten.\n\nBewegen genereert elektrische energieën om je heen voor 6 sec, periodiek oproepen bliksemaanvallen die [(130% Attack/Spell Power)] toebrengen aan nabijgelegen vijanden."}
