MultiLanguageSpellData['nl'][1234387] = {name = "Vlam van Walhallas", additional_info = "[q]Grants 3 extra rangen van Temporal Reliation en 2 extra rangen van Volatile Magics.\n\nTemporale reanimatie\nWanneer u schade absorbeert, breng [(31% Attack/Spell Power)] Arcane schade Back aan de aanvaller en hun aanval Speed verminderen met 20% voor 3 sec.\n\nVluchtige magie\nJullie Critical Strike's hebben de kans om een uitbarsting van magie te creëren, waardoor [(342% Attack/Spell Power)] Arcane schade toebrengt aan vijanden binnen 6 meter van jullie doel.\n\nNaran's Everdisc slaat nu altijd kritiek op Fel Touched vijanden."}
