MultiLanguageSpellData['nl'][1234392] = {name = "Azshara's Ire", additional_info = "[q]Grants 3 extra rangen van Highmountain Fortitude en 2 extra rangen van Deepsurge Crash.\n\nHigh mountain Fortitude\nEens in de 12 seconden, begint u te verzamelen 3% van alle schade als Fortitude. Na 8 sec, Fortitude wordt een beschermende barrière, het absorberen van de hoeveelheid verzameld voor 4 sec.\n\nDeepsurge Crash\nNaga Stunning a Fel Branded vijand barst het, waardoor 0 schade aan nabijgelegen vijanden. Als Deepsurge Crash een Fel Branded vijand beschadigt, barsten ze ook."}
