MultiLanguageSpellData['nl'][1234529] = {name = "Kosmische Maw", additional_info = "Onbeperkt bereik\n1,25 sec gegoten\n[q]De Voidwing versnippert zijn huidige doel tussen stellaire kaken, waardoor 112430647 Fysieke schade.\n\nDe essentie van het doelwit wordt verslonden, waardoor nog eens 4216149 Kosmische schade elke 0,3 sec en toenemende schade van Dimension Adem met 200% gedurende 10 sec. wordt toegebracht."}
MultiLanguageSpellData['nl'][1234531] = {name = "Geactiveerd", additional_info = "Direct\n[q]Een boost van Draconische Energie"}
MultiLanguageSpellData['nl'][1234532] = {name = "Viscerale Strength", additional_info = "Direct\n[q]Blood\nWanneer Vampiric Strike een vijand beschadigt die wordt getroffen door uw Bloedplaag, verlengt het de duur van de ziekte met 3 sec, en behandelt 10% van de resterende schade aan de vijand.\n\nNa de Gift of the San'layn eindigt, de afkoeling van je Death and Decay, en je volgende Heart Strike verbruikt de ziekte om 100% van hun resterende schade aan het doel te dealen.\n\nOnheilig\nWanneer Vampiric Strike een vijand beschadigt die getroffen is door uw Virulent Plague, verlengt het de duur van de ziekte met 3 sec, en behandelt 10% van de resterende schade aan de vijand.\n\nNa Cadeau van de San'layn eindigt, de afkoeling van je Dood en Verval, en je volgende verbruikt de ziekte om 100% van hun resterende schade aan het doel te dealen.\n(1s afkoeling)"}
