MultiLanguageSpellData['nl'][1234547] = {name = "Impression", additional_info = "Onbeperkt bereik\nDirect\n[q]Ilyssa gevangengenomen meerdere spelers, manifesteren een gevangenis die zijn doel wortelt in en brengt 25 Chaos schade aan spelers binnen 3 meter van impact.\n\nDeze gevangenis brengt 7 Chaos schade toe elke 1 sec en wortelt zijn gevangene totdat vernietigd."}
