MultiLanguageSpellData['nl'][1234565] = {name = "Consumeren", additional_info = "Onbeperkt bereik\n2 sec gegoten\n[q]Adarus draineert de essentie van spelers getroffen door Devorer's Ire, het toebrengen van 667557 Kosmische schade en het absorberen van de volgende 2305797 genezing ontvangen.\n\nDeze ontploffing is van toepassing op Oneindige Honger."}
