MultiLanguageSpellData['nl'][1235387] = {name = "Naazindhri's Mystic Lash", additional_info = "Ongeveer 2,5 procs per minuut\n[q]Uw schadelijke spreuken hebben een hoge kans om uw doel te slaan met arcane macht, omgaan ( 644 * 1 ) Arcane schade verdeeld tussen uw doel en vijanden gevangen in zijn pad.\n\nDe schade steeg met 30% per extra vijand, tot 150%, en verder verhoogd met uw Mastery."}
MultiLanguageSpellData['nl'][1235388] = {name = "Bestial Wrath", additional_info = "100 yd bereik\nDirect\n[q]Dire Beasts zal nu uw Kill Command gehoorzamen, de schade dealen bij 30% effectiviteit.\n\nBestial Wrath stuurt nu jouw Dire Beasts in woede, waardoor hun schade wordt vergroot met 15% voor 15 sec. Dire Beasts die worden opgeroepen tijdens een Bestial Wrath zal profiteren van een beperkte duur."}
MultiLanguageSpellData['nl'][1235391] = {name = "Donkere transformatie", additional_info = "100 yd bereik\nDirect\n[q]Uw [ Sludge Belcher : abomination ] [ Glyph of the Geist : geist / ghoul ] deals (44,73% van Attack Power) Schaduwschade aan 5 nabijgelegen vijanden en transformeert in een krachtige ondode monsterlijkheid gedurende 15 sec. [ Dark Transformation : Granting them 100% energy and the / The] [ Sludge Belcher : abomination ] De vermogens van [ Glyph of the Geist : geist / ghoul ] worden versterkt en nemen nieuwe functies aan terwijl de transformatie actief is."}
MultiLanguageSpellData['nl'][1235397] = {name = "Umbral Reach", additional_info = "[q]Beast Mastery\nZwarte pijl periodieke schade verhoogd met 100% en Bleak Powder nu van toepassing op Black Arrow's periodieke effect op alle vijanden het schade.\n\nAls Bleak Powder 2 of meer vijanden beschadigt, krijg je Beast Cleave als je talent hebt.\n\nMarkmanschap\nZwarte pijl periodieke schade verhoogd met 100% en Bleak Powder nu van toepassing op Black Arrow's periodieke effect op alle vijanden het schade.\n\nAls Bleak Powder schade 2 of meer vijanden, krijgen Trick Shots als talent."}
