MultiLanguageSpellData['nl'][1235934] = {name = "Lichthamer", additional_info = "100 yd bereik\nDirect\n[q]Hammer neer uw vijand met de kracht van het Licht, omgaan (580.645% van Aanval Kracht) Heilige schade en (290% van Aanval Kracht) Heilige schade tot 4 nabijgelegen vijanden.\n\nBovendien, roept Empyrean Hammers uit de lucht te slaan 3 nabijgelegen vijanden voor (46,55% van Attack Power) Heilige schade elk."}
MultiLanguageSpellData['nl'][1235946] = {name = "Merk van Ceaseless Ire", additional_info = "Direct\n[q]Het nemen van schade infurieert u, waardoor u te absorberen 202 schade en deal 461 Schaduwschade per infuriatie splitsen tussen nabijgelegen vijanden. De schade steeg met 30% per extra vijand, tot 150%.\n\nU kunt elke 15 sec verder woedend, stapelen tot 15 keer, maar kalmeer snel bij het verlaten van de strijd.\n\nAlleen geldig voor tankspecialisaties."}
MultiLanguageSpellData['nl'][1235959] = {name = "Mage Spellslinger 11.2 Klasse Set 2pc", additional_info = "[q]Arcane\nArcane Blast schade steeg met 12% en Arcane Blast verleent 1 stapel Arcane Harmony. Directe Splinter schade heeft een 25% kans om een stapel Arcane Harmony.\n\nVuur, Frost.\nIce Lance en Icicle schade verhoogd met 10% en Ice Lance heeft een 50% kans om 1 stapel Cold Front te genereren. Directe Splinter schade heeft een 15% kans om een stapel Cold Front te verlenen."}
MultiLanguageSpellData['nl'][1235962] = {name = "Mage Sunfury 11.2 Klasse Set 2pc", additional_info = "[q]Arcane, Vuur, Frost\nSpellfire Sphere spelling schade bonus verhoogd met 1,0%. Mana Cascade verleent nu een extra 0,5% Haste per stack."}
MultiLanguageSpellData['nl'][1235963] = {name = "Mage Frostfire 11.2 Klasse Set 2pc", additional_info = "[q]Fire\nComet Storm en Frostfire Burst schade verhoogd met 15%. Frostfire Bolt schade steeg met 8%. Comet Storm, Frostfire Burst en Frostfire Bolt passen Ignite nu toe op 75% effectiviteit.\n\nArcane, Frost\nMeteor en Frostfire Burst schade verhoogd met 30%. Frostfire Bolt schade steeg met 10%. Meteor, Frostfire Burst en Frostfire Bolt passen nu Ignite toe, waarbij 25% extra schade over 9 sec."}
MultiLanguageSpellData['nl'][1235964] = {name = "Mage Spellslinger 11.2 Klasse Set 4pc", additional_info = "[q]Arcane\nSplinterschade steeg met 8%. Arcane Orb heeft een 100% kans om een stapel Arcane Harmony toe te kennen, tot 8 keer. Bij het bereiken van 20 stapels Arcane Harmony, krijgen Intuïtie op 100% effectiviteit.\n\nVuur\nSplinterschade steeg met 8%. Arcane Orb heeft een 100% kans om een stapel Arcane Harmony toe te kennen, tot 8 keer. Wanneer Cold Front een bevroren bol oproept, verhoog je spreuk schade met 8% voor 10 sec.\n\nFrost\nAls Frozen Orb schade behandelt aan één of meerdere vijanden, heeft het een 15% kans om een stapel Cold Front toe te kennen. Wanneer Cold Front een bevroren bol oproept, verhoog je spreuk schade met 8% voor 10 sec.\n\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1235965] = {name = "Mage Sunfury 11.2 Klasse Set 4pc", additional_info = "[q]Fire, Frost\nUitzonderlijke spreuken van uw Phoenix voegt een extra 0.3 sec toe aan de duur van uw volgende Hyperthermie. Wanneer uw Phoenix verloopt, geeft het u nog meer kracht, waardoor de Minder Tijd Warp en 10% verhoogde spreukschade gedurende 10 sec.\n\nArcane\nUitzonderlijke spreuken van uw Phoenix voegt een extra 0.5 sec toe aan de duur van uw volgende Arcane Ziel. Als je Phoenix afloopt, geeft het je nog meer kracht... en geeft het Lesser Time Warp en 20% verhoogde spreukschade gedurende 10 sec."}
MultiLanguageSpellData['nl'][1235966] = {name = "Mage Frostfire 11.2 Klasse Set 4pc", additional_info = "[q]Arcane, Frost\nCasting Glacial Spike heeft een 100% kans om ook een Pyroblast te werpen, dealer (352.5% van Spell Power) Brandschade. Daarnaast profiteert Pyroblast nu van Ignite.\n\nVuur\nCasting Pyroblast heeft een 20% kans om ook een Glacial Spike dealer (366,24% van Spell Power) Frost schade. Glacial Spikes cast op deze manier niet wortelen. Daarnaast profiteert Glacial Spike nu van Ignite."}
