MultiLanguageSpellData['nl'][1236122] = {name = "Bolts cauteren", additional_info = "Direct\nOngeveer 1,5 procs per minuut\n[q]Uw spreuken en vaardigheden hebben een kans om u te veranderen in een Lightning Rod waardoor stakingen die de laagste gezondheid vriendelijke doel binnen 40 yds voor 450 elke 3 sec voor 15 sec te genezen."}
MultiLanguageSpellData['nl'][1236123] = {name = "Kritieke ketting", additional_info = "[q]Uw spreuken en vermogens hebben de kans om te activeren Kritische Overbelasting, verhogen uw Critical Strike met 31 elke 2 sec voor 20 sec."}
