MultiLanguageSpellData['nl'][1236126] = {name = "Bindende Javelin", additional_info = "100 yd bereik\nDirect\n[q]Taah'bat lanceert arcane speerpunten bij doelspelers, waardoor 2424449 Arcane-schade aan spelers binnen 8 meter van de doelen en het vastbinden van alle spelers getroffen.\n\nElke band veroorzaakt 606112 Arcane schade elke 1 sec en vermindert hun beweging Speed met 50%, toenemende intensiteit om de 5 seconden totdat de speer is vernietigd. Dit effect stapelt zich op."}
MultiLanguageSpellData['nl'][1236127] = {name = "Zieluitwerpen", additional_info = "30 yd bereik\nDirect\n[q]De niet-openbare ziel werpt zich snel uit in de leegte bij de dood, waardoor 2 Arcane schade aan spelers binnen 30 meter."}
MultiLanguageSpellData['nl'][1236128] = {name = "Statische lading", additional_info = "[q]Uw spreuken en vermogens hebben de kans om u Static Charge te verlenen, waardoor uw Versatility gedurende 30 sec met (14 * 20) wordt verhoogd. Elk van uw volgende spreuken en vermogens verminderen de Versatility bonus met 5%."}
MultiLanguageSpellData['nl'][1236129] = {name = "Elektrische stroom", additional_info = "[q]Je krijgt elektrische stroom bij het ingaan van het gevecht, het verhogen van uw Mastery met 8 elke 2 sec tot een maximum van (12 * 8 ) na 24 sec dan fietsen Back naar beneden en herhalen."}
MultiLanguageSpellData['nl'][1236130] = {name = "Bindende Javelin", additional_info = "100 yd bereik\n3 sec gegoten\n[q]Taah'bat lanceert arcane speerpunten bij doelspelers, waardoor 2424449 Arcane-schade aan spelers binnen 8 meter van de doelen en het vastbinden van alle spelers getroffen.\n\nElke band veroorzaakt 606112 Arcane schade elke 1 sec en vermindert hun beweging Speed met 50%, toenemende intensiteit om de 5 seconden totdat de speer is vernietigd. Dit effect stapelt zich op."}
