MultiLanguageSpellData['nl'][1236133] = {name = "Sanctuary Tongues", additional_info = "30 yd bereik\nDirect\n[q]Forces nabijgelegen vijanden te spreken in Sanctuary Tongue, verminderen hun gieten Speed met 10% voor totdat geannuleerd."}
MultiLanguageSpellData['nl'][1236134] = {name = "Energie Shield", additional_info = "[q]Als je schade hebt opgelopen, heb je de kans om een Titan Energy Shield te krijgen die tot 3662 schade gedurende 10 sec. voorkomt. Wanneer de Shield verloopt, behandelt het 30% van de resterende absorptie als Arcane schade gesplitst tussen vijanden binnen 8 yds."}
