MultiLanguageSpellData['nl'][1236145] = {name = "Vlamquills", additional_info = "Direct\n[q]Fire, Frost\nUitzonderlijke spreuken van uw Phoenix voegt een extra 0.3 sec toe aan de duur van uw volgende Hyperthermie. Wanneer uw Phoenix verloopt, geeft het u nog meer kracht, waardoor de Minder Tijd Warp en 10% verhoogde spreukschade gedurende 10 sec.\n\nArcane\nUitzonderlijke spreuken van uw Phoenix voegt een extra 0.5 sec toe aan de duur van uw volgende Arcane Ziel. Als je Phoenix afloopt, geeft het je nog meer kracht... en geeft het Lesser Time Warp en 20% verhoogde spreukschade gedurende 10 sec."}
