MultiLanguageSpellData['nl'][1236160] = {name = "Ignite", additional_info = "Onbeperkt bereik\nDirect\n[q]Uw doel brandt voor een extra 4,0% meer dan 9 sec van de totale directe schade veroorzaakt door uw Fireball, Fire Blast, Scorch, Pyroblast [ Meteor : Meteor ] [ Phoenix Flames : Phoenix Flames ] [ Cinderstorm : Cinderstorm ], en Flamestrike. Als dit effect opnieuw wordt toegepast, zal eventuele resterende schade worden toegevoegd aan de nieuwe Ignite.\n\nVuur Blast zorgt ervoor dat uw Ignites zich verspreiden naar 3 nabijgelegen vijanden."}
MultiLanguageSpellData['nl'][1236161] = {name = "Opgeladen touch", additional_info = "[q]Sparks geactiveerd bij genezing Brann dealen de genezing hoeveelheid als schade aan een vijandelijke doelwit binnen 40yds."}
