MultiLanguageSpellData['nl'][1236207] = {name = "Astral Surge", additional_info = "Onbeperkt bereik\nDirect\n[q]De Arcane Collector springt met energie als het contact opneemt met een Arcane Manifestation, waardoor 22623435 Arcane schade toebrengt aan alle spelers en een extra 8432299 Arcane schade elke 2 sec gedurende 16 sec."}
MultiLanguageSpellData['nl'][1236209] = {name = "Glacial Spike", additional_info = "{1% of base mana} {40 yd range}\n2,75 sec gegoten\n[q]Veroorzaakt een enorme ijspiek, en versmelt je huidige ijsjes erin. Het impaleert je doel, dealt (654% van de Spell Power) schade plus alle schade opgeslagen in uw Iccles, en bevriest het doel op zijn plaats voor 4 sec. Schade kan het bevriezingseffect onderbreken.\n\nVereist 5 Iccles te werpen.\n\nPassief: Ice Lance lanceert geen Iccles meer."}
MultiLanguageSpellData['nl'][1236211] = {name = "Glacial Spike", additional_info = "100 yd bereik\nDirect\n[q]Veroorzaakt een enorme ijspiek, en versmelt je huidige ijsjes erin. Het impaleert je doel, dealt (654% van de Spell Power) schade plus alle schade opgeslagen in uw Iccles, en bevriest het doel op zijn plaats voor 4 sec. Schade kan het bevriezingseffect onderbreken.\n\nVereist 5 Iccles te werpen.\n\nPassief: Ice Lance lanceert geen Iccles meer."}
