MultiLanguageSpellData['nl'][1236253] = {name = "Death Knight Deathbringer 11.2 Klasse Set 2pc", additional_info = "[q]Frost, Unholy\nCasting Reaper's Mark grants 1 stack of Exterminate with 150% first sithe and 125% second sithe doeltreffendheid.\n\nBloed\nCasting Reaper's Mark verleent 2 stapels Exterminate met 150% eerste scythe en 125% tweede scythe effectiviteit."}
MultiLanguageSpellData['nl'][1236254] = {name = "Death Knight Deathbringer 11.2 Klasse Set 4pc", additional_info = "[q]Blood, Frost, Unholy\nVernietig deals 20% toegenomen schade, en Reaper's Mark kan stapelen tot 15 extra keer. Na de explosie verhoogt Reaper's Mark je Critical Strike kans met 10% voor 8 sec.\n(1s afkoeling)"}
MultiLanguageSpellData['nl'][1236256] = {name = "Vorpal Cleave", additional_info = "10 yd bereik\n2,5 sec gegoten\n[q]Caster kraakt het gebied voor hen, waardoor Schaduwschade en het toepassen van een helende absorberen Shield aan spelers getroffen."}
MultiLanguageSpellData['nl'][1236259] = {name = "Death Knight San'layn 11.2 Klasseset 2pc", additional_info = "[q]Onheilig\nInfliction of Sorrow verlengt de duur van uw ziekte met een extra 3,0 sec op uw hoofddoel, en Essence of the Blood Queen verhoogt bovendien uw Mastery met 0,5% per stack.\n\nBloed, Frost.\nInfliction of Sorrow verlengt de duur van uw ziekte met een extra 4.0 sec op uw hoofddoel, en Essence of the Blood Queen verhoogt bovendien uw Mastery met 0,5% per stack."}
MultiLanguageSpellData['nl'][1236260] = {name = "Death Knight San'layn 11.2 Klasse Set 4pc", additional_info = "[q]Onheilig\nInfliction of Sorrow dealt 30% verhoogde schade, en Vampiric Strike verhoogt de schade van uw ghoul met 20% voor 8 sec. Meerdere aanvragen kunnen elkaar overlappen.\n\nBloed, Frost.\nInfliction of Sorrow dealt 50% verhoogde schade, en Vampiric Strike verhoogt de schade van uw Dancing Rune Wapens met 20% voor 8 sec. Meerdere aanvragen kunnen elkaar overlappen."}
MultiLanguageSpellData['nl'][1236262] = {name = "Shaohao's salie slang", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De lessen die Shaohao leerde in leven en dood en de passie die hij voor zijn huis had, zijn samengesmolten in deze etherische slang, een weerspiegeling van de wijsheid van de keizer.\"\nBevordering:\nMist van Pandaria Classic"}
