MultiLanguageSpellData['nl'][1236330] = {name = "Druïde Druïde van de Klauw 11.2 Klasse Set 4pc", additional_info = "[q]Feral\nRavage heeft een kans van 40% om je je doel weer te vernietigen 4 sec later op 100% van de aanvankelijke kracht.\n\nBalance, Guardian, Restauratie\nRavage heeft een kans van 40% om je weer je doel te vernietigen 4 sec later met 60% effectiviteit."}
MultiLanguageSpellData['nl'][1236331] = {name = "Druïde Druïde van de Klauw 11.2 Klasse Set 2pc", additional_info = "[q]Ravage verhoogt uw Haste met 10%, de kans om kritisch toe te slaan met 10%, en de schade uw bloedingen omgaan met 30% gedurende 5 sec.\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236332] = {name = "Druid Elune's gekozen 11.2 klasseset 2pc", additional_info = "[q]Balance\nDe schade aan het sterrenvuur steeg met 15%. Het verkrijgen van Astral Power met Starfire heeft een 40% kans om een Starsurge te lanceren op een slachtoffer met 45% effectiviteit.\n\nFeral, Guardian, Restauratie\nDe schade is met 20% toegenomen. Thrash heeft 40% kans om een Starsurge te lanceren op een slachtoffer met 160% effectiviteit.\n\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236333] = {name = "Druid Elune's gekozen 11.2 klasse Set 4pc", additional_info = "[q]Balance\nOp impact, Starsurges gelanceerd door Starfire splitsen tot maximaal 3 extra doelen op 40% effectiviteit en verlenen een stapel van Gathering Moonlight. Gieten Furie van Elune of Volle Maan verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec.\n\nFeral, Guardian, Restauratie\nOp impact, Starsurges gelanceerd door Thrash splitsen tot maximaal 3 extra doelen op 20% effectiviteit en verlenen een stapel Gathering Moonlight. Afgietsel Maanstraal verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec."}
MultiLanguageSpellData['nl'][1236334] = {name = "Druïde Keeper van de Grove 11.2 Klasse Set 2pc", additional_info = "[q]Balance, Feral, Guardian\nCasting Galactische Uitlijning roept de hulp van een dryad voor 10 sec die werpt Starsurge op 360% effectiviteit en Starfall op 800% effectiviteit.\n\nHerstel\nCasting Incarnation: Boom van het Leven of Convoce de Geesten roept de hulp van een droogtrommel voor 5 sec die Tranquility werpt op 50% effectiviteit en onmiddellijk hergroeit uw laagste gezondheid bondgenoot met 200% effectiviteit."}
MultiLanguageSpellData['nl'][1236336] = {name = "Druïde Keeper van de Grove 11.2 Klasse Set 4pc", additional_info = "[q]Balance, Feral, Guardian\nWanneer uw Dryad vervaagt, uw volgende 2 Starsurges schade voor een extra bedrag gelijk aan 3% van uw schade gedaan terwijl het actief was en spatten 10% van hun schade op nabijgelegen vijanden, gereduceerd tot meer dan 5 doelen.\n\nHerstel\nWanneer uw Dryad vervaagt, genezen uw volgende 2 Swiftmends voor een extra bedrag gelijk aan 5% van uw genezing gedaan terwijl het actief was en spetteren 25% van hun genezing op nabijgelegen bondgenoten, gereduceerd tot meer dan 5 doelen."}
MultiLanguageSpellData['nl'][1236337] = {name = "Druid Wildstalker 11.2 Klasse Set 2pc", additional_info = "[q]Feral\nHet tempo waarmee Bloodseeker Vines groeit, wordt met 40% verhoogd. Tiger's Fury zorgt ervoor dat Bloodseeker Vines groeien op maximaal 3 geldige nabijgelegen vijanden.\n\nBalance, Guardian, Restauratie\nDe snelheid waarmee Symbiotic Blooms groeit, wordt met 45% verhoogd. Gieten Hergroei met Clearcasting zorgt ervoor dat Symbiotic Blooms groeien op maximaal 2 geldige nabijgelegen bondgenoten."}
MultiLanguageSpellData['nl'][1236338] = {name = "Druid Wildstalker 11.2 Klasse Set 4pc", additional_info = "[q]Feral\nBloedzoeker Vines hebben een 20% kans om Bursting Growth elke 2 sec op 100% effectiviteit te activeren. Elke stapel Bloodseeker Vines op een vijand verhoogt Bursting Groei schade genomen met 40%.\n\nBalance, Guardian, Restauratie\nSymbiotische Blooms hebben een 35% kans om Bursting Groei elke 2 sec op 100% effectiviteit te activeren. Elke stapel van Symbiotic Blooms op een bondgenoot verhoogt Bursting Groei genezing genomen met 30%."}
MultiLanguageSpellData['nl'][1236342] = {name = "Voorbereiden van staking", additional_info = "Direct\n[q]Feral\nRavage heeft een kans van 40% om je je doel weer te vernietigen 4 sec later op 100% van de aanvankelijke kracht.\n\nBalance, Guardian, Restauratie\nRavage heeft een kans van 40% om je weer je doel te vernietigen 4 sec later met 60% effectiviteit."}
MultiLanguageSpellData['nl'][1236343] = {name = "Abyssale detonatie", additional_info = nil}
MultiLanguageSpellData['nl'][1236348] = {name = "Opgeladen slash", additional_info = "100 yd bereik\n{4 sec cast} {3 sec cooldown}\n[q]Zo'phex laadt zijn zwaarden op en ontketent een enorme slag, waardoor 15758921 Fysische schade wordt toegebracht aan alle vijanden waar hij bij is."}
MultiLanguageSpellData['nl'][1236350] = {name = "Void Power Shard Vrijgegeven Beelden - Cosmetic", additional_info = nil}
MultiLanguageSpellData['nl'][1236354] = {name = "Soul Siphon", additional_info = "40 yd bereik\n{2 sec cast} {5 sec cooldown}\n[q]Caster vertraagt hun doel en draineert 622547 gezondheid over 8 sec, genezing van de caster voor twee keer de hoeveelheid drainage."}
MultiLanguageSpellData['nl'][1236355] = {name = "Death Knight Rijder van de Apocalyps 11.2 Klasseset 2pc", additional_info = "[q]Blood, Unholy\nApocalyps roept Whitemane nu 10 seconden op. Whitemane's Undeath dealt 20% meer schade en infecteert 1 extra doel als het zich verspreidt, en haar Death Coil dealt 35% meer schade.\n\nFrost\nDe pilaar van Frost roept nu Trollbane voor 10 sec. Trollbane's Icy Fury dealt 20% meer schade... en zijn obliterate dealt 15% meer schade."}
MultiLanguageSpellData['nl'][1236356] = {name = "Death Knight Rider van de Apocalyps 11.2 Klasse Set 4pc", additional_info = "[q]Blood, Unholy\nCasting Death Coil of Epidemic beveelt Whitemane om haar Death Coil of Epidemic naast je te werpen met 125% effectiviteit. Jouw doodsoorzaak is 40% meer schade aan doelwitten dan Whitemane's dood.\n\nFrost\nHet Casting Obliterate of Frostscyde beveelt Trollbane om zijn Obliterate of Frostscythe naast je te werpen met 100% effectiviteit. Jouw obliterate dealt 20% meer schade aan doelen beïnvloed door Trollbane's Icy Fury.\n\n(500m afkoeling)"}
MultiLanguageSpellData['nl'][1236358] = {name = "Demon Hunter Aldrachi Reaver 11.2 Klasseset 2pc", additional_info = "[q]Reaver's Glaive schade wordt verhoogd met 50% en andere fysieke schade wordt verhoogd met 25%."}
MultiLanguageSpellData['nl'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Klasse Set 4pc", additional_info = "[q]Havoc\nFurie van de Aldrachi geeft Blade Dance nog meer kracht na Chaos Strike, waardoor het aantal snijwonden toeneemt tot 12.\n\nReaver's Mark stapelt nu tot 2 keer en versterkt verder Chaos Strike wanneer gegoten na Blade Dance, het toepassen van een extra stack voor 100% van de normale duur.\n\nWraak\nFurie van de Aldrachi versterkt verder Ziel Cleave wanneer gegoten na Shear, toenemende slashes tot 12.\n\nReaver's Mark stapelt nu tot 2 keer en versterkt Shear wanneer gegoten na Soul Cleave, het toepassen van een extra stack voor 100% van de normale duur."}
MultiLanguageSpellData['nl'][1236361] = {name = "Demon Hunter Fel-Scarred 11.2 Klasseset 2pc", additional_info = "[q]Havoc\nImmolation Aura behandelt 30% toegenomen schade en verhoogt Chaos Strike schade met 20% terwijl actief.\n\nWraak\nImmolation Aura behandelt 30% verhoogde schade en verhoogt de Soul Cleave schade met 20% terwijl ze actief is."}
MultiLanguageSpellData['nl'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Klasse Set 4pc", additional_info = "[q]Havoc\nHet betreden van demonenvorm leidt nu onmiddellijk tot een Demonchirurgie en verbrijzelt een demonenzielfragment dat 20% verhoogde schade geeft gedurende 10 sec.\n\nWraak\nHet betreden van demonenvorm leidt nu onmiddellijk tot een Demonsurge en verbrijzelt een demonenzielfragment dat 20% verhoogde schade geeft gedurende 15 sec.\n\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236364] = {name = "Evoker Flameshaper 11.2 Klasseset 2pc", additional_info = "[q]Bevrijding\nEngulf stookt uw Innerlijke Vlam, verhoogt uw schade en genezing in de loop van de tijd met 15% en verhoogt uw kans om Essence Burst te krijgen met 50% voor 12 sec. Stacks tot 2 keer. Meerdere aanvragen kunnen elkaar overlappen.\n\nBehoud, Augmentatie\nEngulf stikt uw Innerlijke Vlam, verhoogt uw schade en genezing in de loop van de tijd met 25% en vergroot uw kans om Essence Burst te krijgen met 50% voor 12 sec. Stacks tot 2 keer. Meerdere aanvragen kunnen elkaar overlappen."}
MultiLanguageSpellData['nl'][1236365] = {name = "Evoker Flameshaper 11.2 Klasse Set 4pc", additional_info = "[q]Bevrijding\nHet consumeren van Essence Burst tijdens Inner Flame vuurt een Essence Bomb op uw doel, schadelijk voor nabijgelegen vijanden voor (371% van Spell Power) Arcane, gereduceerd tot meer dan 5 doelen.\n\nBehoud, Augmentatie\nHet consumeren van Essence Burst tijdens Inner Flame vuurt een Essence Bomb op uw doel, helende nabijgelegen bondgenoten voor (250% van Spell Power), gereduceerd tot meer dan 5 doelen."}
MultiLanguageSpellData['nl'][1236366] = {name = "Evoker Schaalcommander 11.2 Klasseset 2pc", additional_info = "[q]augmentatie\nTijdens het vliegen tijdens Deep Breath en 20 seconden daarna, voer je het bevel over een eskader van 2 Dracthyr die je doelwitten zal aanvallen met Disintegrate en Pyre.\n\nVernietiging, conservering\nTijdens het vliegen tijdens Deep Breath en 10 seconden daarna, voer je het bevel over een eskader van 2 Dracthyr die je doelwitten zal aanvallen met Disintegrate en Pyre."}
MultiLanguageSpellData['nl'][1236367] = {name = "Evoker Scalecommander 11.2 Klasse Set 4pc", additional_info = "[q]Bevrijding\nTerwijl je eskader actief is, valt je Mass Disintegrate tot 2 extra doelwitten aan. Bovendien helpt je eskader je nog 5 seconden.\n\nAugmentatie\nTerwijl je eskader actief is, slaat je massale uitbarsting tot twee extra doelen. Bovendien helpt je eskader je nog 10 seconden.\n\nBehoud\nTerwijl je eskader actief is, slaat je massale uitbarsting tot twee extra doelen. Bovendien helpt je eskader je nog 5 seconden."}
MultiLanguageSpellData['nl'][1236368] = {name = "Evoker Chronowarden 11.2 Klasseset 2pc", additional_info = "[q]Tip de afkoeling van de Scales wordt verminderd met 60 sec."}
MultiLanguageSpellData['nl'][1236369] = {name = "Evoker Chronowarden 11.2 Klasse Set 4pc", additional_info = "[q]Temporal Burst zorgt ervoor dat Chrono Flames 2 extra doelen aanvallen en herhalen 15% extra schade of genezing, tot een maximum van [(Spell Power * 4.5) * (1 + Versatility)], en verhoogt Essence vermogen schade en genezing met 30%."}
MultiLanguageSpellData['nl'][1236370] = {name = "Hunter Dark Ranger 11.2 Klasse Set 2pc", additional_info = "[q]Beast Mastery\nDe schade aan de pijlen van de zwarte pijl nam met 10% toe en de schade aan het blauwpoeder nam met 20% toe. De afkoeling van Call of the Wild wordt verminderd met 60 sec.\n\nMarkmanschap, Survival\nDe schade aan de pijlen van de zwarte pijl nam met 10% toe en de schade aan het blauwpoeder nam met 20% toe. De afkoeling van Trueshot wordt verminderd met 30 sec."}
MultiLanguageSpellData['nl'][1236371] = {name = "Hunter Dark Ranger 11.2 Klasse Set 4pc", additional_info = "[q]Beast Mastery, Marksmanship, Survival\nDe Black Arrow schade van Withering Fire is met 50% toegenomen. Consuming Deathblow heeft een 50% kans om alle Black Arrow barrages tijdens uw volgende Withering Fire te vuren 1 extra Black Arrow."}
MultiLanguageSpellData['nl'][1236372] = {name = "Hunter Pack Leader 11.2 Klasse Set 2pc", additional_info = "[q]Markmanschap, Survival\nDe schade aan huisdieren steeg met 15% en de schade aan het beest met 15%. Het oproepen van een Beest verleent 6% Haste, Mastery, of Critical Strike kans op basis van het Beest opgeroepen voor 8 sec.\n\nBeast Mastery\nDe schade aan huisdieren steeg met 5% en de schade aan het beest met 15%. Het oproepen van een Beest verleent 6% Haste, Mastery, of Critical Strike kans op basis van het Beest opgeroepen voor 8 sec."}
MultiLanguageSpellData['nl'][1236373] = {name = "Hunter Pack Leader 11.2 Klasse Set 4pc", additional_info = "[q]Summoning a Beast terwijl onder de effecten van Lead from the Front de nabijgelegen wilde dieren in een Stampede, opladen van uw doel en dealen [(300% of Attack Power) * 9] Fysieke schade tot maximaal 8 vijanden over 7 sec."}
MultiLanguageSpellData['nl'][1236374] = {name = "Hunter Sentinel 11.2 Klasse Set 2pc", additional_info = "[q]Marksmanschap\nSnelle brandschade steeg met 25%. Wanneer Lunar Storm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Aimed Shots om Arcane schade te dealen en hun schade verhoogd met 10%.\n\nBeast Mastery, Overleving\nDe schade aan de bom is met 10% toegenomen. Wanneer Maanstorm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Wildfire Bombs om Arcane schade te behandelen en hun initiële schade verhoogd met 150%."}
MultiLanguageSpellData['nl'][1236375] = {name = "Hunter Sentinel 11.2 Klasse Set 4pc", additional_info = "[q]Marksmanschap\nSentinel's schade wordt verhoogd met 18%. De Boon van Elune is nu actief voor de duur van Maanstorm bij 100% effectiviteit.\n\nBeast Mastery, Overleving\nSentinel's schade is verhoogd met 20%. De Boon van Elune is nu actief voor de duur van Maanstorm bij 100% effectiviteit."}
MultiLanguageSpellData['nl'][1236376] = {name = "Soul Ravel", additional_info = nil}
MultiLanguageSpellData['nl'][1236377] = {name = "Monk Master of Harmony 11.2 Klasse Set 2pc", additional_info = "[q]Brewmaster\nHet verkrijgen van vitaliteit heeft een toenemende kans om uw volgende Tiger Palm om een Harmonic Surge los te laten, dealen [180 * (400% of Spell Power) / 100] Natuurschade verdeeld tussen uw doel en andere nabijgelegen vijanden, en [20 * (500% of Spell Power) / 100] genezing tot maximaal 5 gewonde bondgenoten.\n\nWindwalker, Mistweaver\nHet verkrijgen van vitaliteit heeft een toenemende kans om uw volgende Tiger Palm om een Harmonic Surge los te laten, dealen [20 * (400% of Spell Power) / 100] Natuurschade verdeeld tussen uw doel en andere nabijgelegen vijanden, en [90 * (500% of Spell Power) / 100] genezing tot maximaal 5 gewonde bondgenoten."}
MultiLanguageSpellData['nl'][1236378] = {name = "Monkmeester van Harmonie 11.2 Klasse Set 4pc", additional_info = "[q]Windwalker, Mistweaver\nCasting Thunder Focus Tea garandeert dat uw volgende 2 afgietsels van Tiger Palm een Harmonic Surge zal veroorzaken.\n\nBrewmaster\nCasting garandeert dat je volgende 2 afgietsels van Tiger Palm een Harmonic Surge zal veroorzaken."}
MultiLanguageSpellData['nl'][1236379] = {name = "Monk Shado-Pan 11.2 Klasseset 2pc", additional_info = "[q]Brewmaster\nFlury Strikes deal 10% meer schade en het activeren van Weapons of Order direct verleent 10 stapels van Flury Strikes die leiden tot uw volgende aanval op 70% effectiviteit.\n\nWindwalker, Mistweaver\nFlury Strikes deal 20% meer schade en het activeren van Storm, Aarde, en Vuur onmiddellijk verleent 10 stapels Flury Strikes die trigger op uw volgende aanval op 70% effectiviteit."}
MultiLanguageSpellData['nl'][1236380] = {name = "Monk Shado-Pan 11.2 Klasse Set 4pc", additional_info = "[q]Brewmaster\nDe stroomtoevoer wordt verhoogd met 30% en Flury Strikes activeert elke 150 energie die tijdens de Wapens van Orde wordt verbruikt.\n\nWindwalker\nVloeistof lading generatie wordt verhoogd met 50% en Flury Strikes triggers elke 120 energie besteed tijdens Storm, Aarde en Vuur.\n\nMistweaver\nDe opladingsproductie wordt met 50% verhoogd en Flury Strikes activeert elke 150 energie die tijdens de Wapens van Orde wordt verbruikt."}
MultiLanguageSpellData['nl'][1236381] = {name = "Monk Conduit van de Hemelen 11.2 Klasse Set 2pc", additional_info = "[q]Windwalker\nHart van de Jade Serpent bovendien triggers voor 4 sec op 100% effectiviteit nadat u Slicing Winds.\n\nBrouwmeester, Mistweaver\nHart van de Jade Serpent extra triggers voor 8 sec op 100% effectiviteit nadat u Thunder Focus Thee.\n\n(1s afkoeling)"}
MultiLanguageSpellData['nl'][1236382] = {name = "Monk Conduit van de Hemelen 11.2 Klasse Set 4pc", additional_info = "[q]Hart van de Jade Slang verhoogt uw Haste met 10% terwijl u actief bent en 4 sec daarna."}
MultiLanguageSpellData['nl'][1236383] = {name = "Paladin Herald van de Zon 11.2 Klasse Set 2pc", additional_info = "[q]Retributie\nDawnlight's genezing en schade wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra [10][10] sec.\n\nBescherming\nDawnlight's genezing en schade wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra [10][10] sec.\n\nHoly (Avenging Wrath)\nDawnlight's genezing en schade wordt verhoogd met 60% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra 10[10][10] sec."}
MultiLanguageSpellData['nl'][1236384] = {name = "Paladin Herald van de Zon 11.2 Klasse Set 4pc", additional_info = "[q]Retributie\nZonne Wrath verhoogt de effectiviteit van uw Heilige Kracht besteden met 15% en verleent u [2][2] Dawnlight.\n\nBescherming\nZonne Wrath verhoogt de effectiviteit van uw Heilige Kracht besteden met 15% en verleent u [2][2] Dawnlight.\n\nHoly (Avenging Wrath)\nZonne Wrath verhoogt de effectiviteit van uw Heilige Kracht besteden met 30% en verleent u 2[2][2] Dawnlight."}
MultiLanguageSpellData['nl'][1236385] = {name = "Soul Strafe", additional_info = nil}
MultiLanguageSpellData['nl'][1236389] = {name = "Paladin Lightsmith 11.2 Klasse Set 2pc", additional_info = "[q]Bescherming\nDe schade van Hammer en Anvil wordt met 15% verhoogd en kan ook met 40% worden geactiveerd.\n\nVergelding\nHammer en Anvil's genezing wordt verhoogd met 15% en het kan ook worden geactiveerd door Crusader Strike bij 40% effectiviteit.\n\nHeilige\nHammer en Anvil's genezing wordt verhoogd met 15% en het kan ook worden geactiveerd door Crusader Strike bij 75% effectiviteit.\n\n(750m afkoeling)"}
MultiLanguageSpellData['nl'][1236390] = {name = "Paladin Lightsmith 11.2 Klasse Set 4pc", additional_info = "[q]Hammer en Anvil verlenen ook een stapel meesterwerk, waardoor uw volgende Heilige Bewapening een kleinere versie van zichzelf op een nabijgelegen bondgenoot voor elke stack werpen."}
MultiLanguageSpellData['nl'][1236391] = {name = "Paladin Templar 11.2 Klasse Set 2pc", additional_info = "[q]Uw Empyrean Hammer deals 20% toegenomen Critical Strike schade en de Critical Strikes hebben 50% kans om een extra stapel van Light's Deliverance te verlenen.\n(Probleem: 50%)"}
MultiLanguageSpellData['nl'][1236392] = {name = "Paladin Tempeliers 11,2 Klasse Set 4pc", additional_info = "[q]Holy, Bescherming\nHammer of Light dealt 35% verhoogde schade aan zijn primaire doel, slaat 3 extra secundaire doelen, en kan nu worden gegoten 1 keer na Eye of Tyr.\n\nVergelding\nHammer of Light dealt 35% verhoogde schade aan zijn primaire doel, slaat 3 extra secundaire doelen, en kan nu worden gegoten 1 keer na Wake of Ashes."}
MultiLanguageSpellData['nl'][1236394] = {name = "Priester Oracle 11.2 Klasse Set 2pc", additional_info = "[q]Holy, Shadow\nCasting Prayer of Mending geneest je doel voor (1400% van Spell Power).\n\nVakgebied\nDe eerste bout van elke Penance cast schade of genezing voor 200% meer."}
MultiLanguageSpellData['nl'][1236395] = {name = "Priester Oracle 11.2 Klasse Set 4pc", additional_info = "[q]Casting Premonition of Fiety or Premonition of Solace verleent 2 stapels voorgevoel van Insight op 100% effectiviteit. Het consumeren van een stapel van Voorgevoel van Insight verhoogt uw Haste met 1,0% voor 10 sec. Meerdere aanvragen kunnen elkaar overlappen."}
MultiLanguageSpellData['nl'][1236396] = {name = "Priester Voidweaver 11.2 Klasseset 2pc", additional_info = "[q]Discipline\nVoid Blast en Penance schade wordt verhoogd met 30% en Void Blast's gegoten tijd wordt verminderd met 20%.\n\nHeilige\nVoid Blast schade wordt verhoogd met 30% en Void Blast's gegoten tijd wordt verminderd met 20%.\n\nSchaduw\nVoid Blast schade wordt verhoogd met 30% en Void Blast's gegoten tijd wordt verminderd met 20%. De afkoeling van Void Blast is met 50% verminderd."}
MultiLanguageSpellData['nl'][1236397] = {name = "Priester Voidweaver 11.2 Klasse Set 4pc", additional_info = "[q]Discipline\nVoid Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Leid verhoogt Entropic Rift's schade met nog eens 10%, en de schade van je volgende Mind Blast wordt verhoogd met maximaal 300% op basis van de grootte van Entropic Rift wanneer het instort.\n\nHeilige\nVoid Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Leegte verhoogt Entropic Rift's schade met nog eens 10%, en de schade van uw volgende Void Torrent wordt verhoogd met maximaal 200% op basis van de grootte van Entropic Rift wanneer het instort.\n\nSchaduw\nVoid Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Leid verhoogt Entropic Rift's schade met nog eens 10%, en de schade van uw volgende Void Torrent wordt verhoogd met maximaal 60% op basis van de grootte van Entropic Rift wanneer het instort."}
MultiLanguageSpellData['nl'][1236398] = {name = "Priester Archon 11.2 Klasse Set 2pc", additional_info = "[q]schaduw\nHalos genereren een extra 10 waanzin meer dan 5 sec en Resonant Energie verhoogt bovendien de schade van uw Devouring Plague met 5,0%.\n\nDiscipline, Holy\nHalos verminderen de afkoeling van uw Heilig Woord: Sereniteit en Heilig Woord: Sanctificeren met 5 sec en Resonante Energie verhoogt bovendien de genezing van uw Heilige Woorden met 5,0%."}
MultiLanguageSpellData['nl'][1236399] = {name = "Priester Archon 11.2 Klasse Set 4pc", additional_info = "[q]Discipline, Shadow\nTerwijl Power Surge is actief, elke 2 casts van Devouring Plague voegt een andere Halo aan het effect bij 100% effectiviteit, maximaal 2 keer.\n\nHeilige\nTerwijl Power Surge actief is, elke 2 afgietsels van Heilig Woord: Sereniteit of Heilig Woord: Sancitify voegt een andere Halo aan het effect bij 100% effectiviteit, tot 2 keer."}
MultiLanguageSpellData['nl'][1236400] = {name = "Rogue Deathstalker 11.2 Klasse Set 2pc", additional_info = "[q]Assassinatie\nShiv verhoogt de effectiviteit van alle Deathstalker schade-effecten en schade bonussen met 60% terwijl actief.\n\nOutlaw, Subtiliteit\nSymbolen van de dood verhoogt de effectiviteit van alle Deathstalker schade effecten en schade bonussen met 40% terwijl actief."}
MultiLanguageSpellData['nl'][1236401] = {name = "Rogue Deathstalker 11.2 Klasse Set 4pc", additional_info = "[q]Assassinatie\nShiv heeft 3 sec langere duur en verbruikt een toepassing van uw actieve Deathstalker's Mark wanneer geactiveerd.\n\nOutlaw, Subtiliteit\nSymbolen van de dood heeft 3 sec verlengd duur en verbruikt een toepassing van uw actieve Deathstalker's Mark wanneer geactiveerd."}
MultiLanguageSpellData['nl'][1236402] = {name = "Rogue Fatebound 11.2 Klasse Set 2pc", additional_info = "[q]Outlaw\nGhostly Strike dealt 50% verhoogde schade en heeft 4 sec langere duur.\n\nEdge Case draait nu een extra Fatebound Coin en activeert Ghostly Strike activeert het effect.\n\nMoord, Subtiliteit\nKingsbane behandelt 10% verhoogde schade en heeft 4 sec langere duur.\n\nEdge Case draait nu een extra Fatebound Coin en activeert Kingsbane activeert zijn effect."}
MultiLanguageSpellData['nl'][1236403] = {name = "Rogue Fatebound 11.2 Klasse Set 4pc", additional_info = "[q]Outlaw\nMet een gelukkige Fatebound Coin vermindert de afkoeling van Adrenaline Rush met 30.0 sec en Ghostly Strike met 15.0 sec.\n\nMoord, Subtiliteit\nMet een gelukkige Fatebound Coin vermindert de afkoeling van Deathmark met 30.0 sec en Kingsbane met 15.0 sec."}
MultiLanguageSpellData['nl'][1236404] = {name = "Rogue Trickster 11.2 Klasse Set 2pc", additional_info = "[q]Unseen Blade dealt 35% verhoogde schade en heeft een 35% kans om twee keer toe te slaan."}
MultiLanguageSpellData['nl'][1236405] = {name = "Rogue Trickster 11.2 Klasse Set 4pc", additional_info = "[q]Coup de Grace kan nu worden geactiveerd een tweede keer binnen 5 sec, het omgaan met 150% van de normale schade."}
MultiLanguageSpellData['nl'][1236406] = {name = "Shaman Farseer 11.2 Klasse Set 2pc", additional_info = "[q]Ancestral Swiftness roept gedurende 15 sec een erkende Voorouder op die 10% meer schade en genezing behandelt."}
MultiLanguageSpellData['nl'][1236407] = {name = "Shaman Farseer 11.2 Klasse Set 4pc", additional_info = "[q]Restoratie\nVoorouderlijke Snelheid verhoogt de schade en genezing van uw spreuken met 25%, vermindert de mana kosten van uw spreuken met 25%, en verhoogt de oplaadsnelheid van Lava Burst en Riptide met 50% voor 8 sec.\n\nElementaire, verbetering\nVoorouderlijke Snelheid verhoogt de schade en genezing van uw spreuken met 25%, vermindert de mana kosten van uw spreuken met 25%, en verhoogt de oplaadsnelheid van Lava Burst met 50% voor 8 sec."}
MultiLanguageSpellData['nl'][1236408] = {name = "Sjamaan Stormbringer 11.2 Klasse Set 2pc", additional_info = "[q]Versterking, Herstel\nAscendance heeft een 100% kans om een lading Tempest toe te kennen en elke 8 Ontwakende Stormen activeert nu Ascendance voor 6,0 sec.\n\nElementaal\nAscendance heeft een 100% kans om een lading Tempest toe te kennen en elke 9 Ontwakende Stormen activeert nu Ascendance voor 6,0 sec.\n\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236409] = {name = "Shaman Stormbringer 11.2 Klasse Set 4pc", additional_info = "[q]Elementaal, herstel\nNatuurschade steeg met 3,0%, en Ascendance machtigt uw volgende 2 Tempests om een storm boven te verzamelen die deals (960% van Spell Power) Natuurschade aan zijn primaire doel en verminderde schade aan nabijgelegen vijanden na 1,5 sec.\n\nVerbetering\nDe schade aan de natuur nam met 5,0% toe, en Ascendance machtigt jullie volgende 2 Tempesten om een storm boven te verzamelen die deals (400% van Attack Power) Natuurschade aan zijn primaire doel en verminderde schade aan nabijgelegen vijanden na 1,5 sec.\n\n(100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236410] = {name = "Sjamaan Totemic 11.2 Klasse Set 2pc", additional_info = "[q]Elementaal, herstel\nNadat u alle Whirling Element Motes verbruikt, werpt u Downpour op 200% effectiviteit op de locatie van uw Susting Totem.\n\nVerbetering\nNadat u alle Whirling Element Motes verbruikt, werpt uw Susting Totem Primordial Storm op 200% effectiviteit op de locatie."}
MultiLanguageSpellData['nl'][1236411] = {name = "Sjamaan Totemic 11.2 Klasse Set 4pc", additional_info = "[q]Elementaal, herstel\nNa het casten van Downpon werpt uw volgende Chain Heal, Healing Wave of Healing Surge opnieuw met 150% effectiviteit.\n\nVerbetering\nNa het casten van Primordial Storm werpt uw volgende Lava Lash of Fire Nova opnieuw op 150% effectiviteit.\n\n(500m afkoeling)"}
