MultiLanguageSpellData['nl'][1236413] = {name = "Warlock Hellcaller 11.2 Klasse Set 2pc", additional_info = "[q]Demonologie, Vernietiging\nMark van Xavius verhoogt Blackened Soul schade met een extra 3% per stack. Malevolence verhoogt het aantal stapels van Wither met 2 extra stapels.\n\nAfwikkeling\nMark van Xavius verhoogt Blackened Soul schade met een extra 6% per stack. Malevolence verhoogt het aantal stapels van Wither met 2 extra stapels."}
MultiLanguageSpellData['nl'][1236414] = {name = "Warlock Hellcaller 11.2 Klasse Set 4pc", additional_info = "[q]Demonologie, Vernietiging\nCasting Malevolence verleent 2 stapels Backdraft en voorkomt Blackened Soul te verbruiken stacks terwijl het omgaan met schade 15% sneller voor 8 sec.\n\nAfwikkeling\nCasting Malevolence verleent 2 stapels getormenteerde Crescendo en voorkomt Blackened Soul van het consumeren van stapels terwijl het omgaan met schade 25% sneller voor 8 sec."}
MultiLanguageSpellData['nl'][1236415] = {name = "Warlock Soul Harvester 11.2 Klasse Set 2pc", additional_info = "[q]Shadow of Death ontketent je demonische ziel om je huidige doelwit voor 9 sec aan te vallen, dealend (279.306% van Spell Power) Schaduwschade en (186.209% van Spell Power) Schaduwschade aan vijanden binnen 10 yds met elke swipe."}
MultiLanguageSpellData['nl'][1236416] = {name = "Warlock Soul Harvester 11.2 Klasse Set 4pc", additional_info = "[q]Demonische Zielschade nam toe met 45% en Wicked Reaping-schade met 45%. Je demonische ziel genereert elke 3 seconden 1 Soul Shard terwijl je vijanden aanvalt."}
MultiLanguageSpellData['nl'][1236417] = {name = "Warlock Diabolist 11.2 Klasse Set 2pc", additional_info = "[q]Vernietiging, Vernietiging\nCasting Chaos Bolt, Rain of Fire, of Shadowburn roept een Demonische Oculus op, tot 3. Consuming Demonic Art flends your Demonic Oculi at your current target, exploding for (502.813% of Spell Power) Brandschade en (335.172% van Spell Power) Brand schade aan vijanden binnen 10 yds.\n\nDemonologie\nDe hand van Gul'dan op volle kracht roept een Demonische Oculus op, tot 3. Consuming Demonic Art flends your Demonic Oculi at your current target, exploding for (502.813% of Spell Power) Brandschade en (335.172% van Spell Power) Brand schade aan vijanden binnen 10 yds."}
MultiLanguageSpellData['nl'][1236418] = {name = "Warlock Diabolist 11.2 Klasse Set 4pc", additional_info = "[q]Demonische Oculi analyseert de strijd terwijl ze actief zijn en levert informatie aan u terwijl ze exploderen, waardoor uw Intellect gedurende 10 sec met 2% wordt verhoogd."}
MultiLanguageSpellData['nl'][1236419] = {name = "Krijger Colossus 11.2 Klasse Set 2pc", additional_info = "[q]Vernietig de schade verhoogd met 20% en Critical Strike schade van uw vaardigheden wordt verhoogd met maximaal 20% op de doelen beïnvloed door uw Sloop voor 10 sec gebaseerd op het aantal stapels Colossal Might geconsumeerd."}
MultiLanguageSpellData['nl'][1236420] = {name = "Krijger Colossus 11.2 Klasse Set 4pc", additional_info = "[q]ARMEN\nSloop verhoogt de Critical Strike kans op uw volgende 1 Stervelingstaking met 100%. Mortal Strike Critical Strikes verhogen uw Rend en Deep Wounds schade met 80% gedurende 8 sec.\n\nFury, Bescherming\nSloop verhoogt de Critical Strike kans op uw volgende 1 Shield Slam met 100%. Shield Slam Critical Strikes verhogen uw Rend en Deep Wounds schade met 80% gedurende 8 sec."}
MultiLanguageSpellData['nl'][1236421] = {name = "Warrior Mountain Thane 11.2 Klasse Set 2pc", additional_info = "[q]Thunder Blast heeft een 35% kans om 5 Ionizing Strikes neer te halen op de getroffen doelen. Elke staking deals (150% van Attack Power) Natuurschade."}
MultiLanguageSpellData['nl'][1236422] = {name = "Warrior Mountain Thane 11.2 Klasse Set 4pc", additional_info = "[q]Ionizing Strikes dealen 100% meer schade en wanneer u Ionizing Strikes activeert, krijgt u een lading van Thunder Blast en uw volgende Thunder Blast deals 100% extra schade."}
MultiLanguageSpellData['nl'][1236423] = {name = "Warrior Slayer 11.2 Klasse Set 2pc", additional_info = "[q]Uitvoeren schade verhoogd met 10% en Executes van Plotselinge Dood hebben een 10% kans per stapel Overweldigd op het doel om een Slayer's Strike te activeren op 100% effectiviteit."}
MultiLanguageSpellData['nl'][1236424] = {name = "Warrior Slayer 11.2 Klasse Set 4pc", additional_info = "[q]ARMEN\nOverpower schade verhoogd met 10% en Overpower heeft een 2% kans per stapel Overpowered op het doel om Reap de Storm te activeren op 150% effectiviteit.\n\nFury, Bescherming\nRaging Blow schade verhoogd met 10% en Raging Blow heeft een 2% kans per stapel Overweldigd op het doel om Reap de Storm te activeren op 150% effectiviteit.\n\n(500m afkoeling)"}
