MultiLanguageSpellData['nl'][1236689] = {name = "Leegte verminderen", additional_info = "Direct\n[q]Het nemen van schade heeft een grote kans om ervoor te zorgen dat u de essentie van nabijgelegen vijanden te verslinden, dealen 2116 Schaduw schade verdeeld tussen hen en u genezen voor 150% van de schade behandeld.\n\nDodelijke schade niet hoger dan 18656 in plaats daarvan herstelt u tot 20% gezondheid en reconstitueert u als onstabiele leegte voor 6 sec. Overtrof 50% gezondheid om de dood te stabiliseren en te voorkomen. Dit effect kan eenmaal per 8 minuten optreden. De Nucleus kan geen schade aanrichten tijdens het opladen."}
