MultiLanguageSpellData['nl'][1236807] = {name = "Dryad's favor", additional_info = "Direct\n[q]Balance, Feral, Guardian\nWanneer uw Dryad vervaagt, uw volgende 2 Starsurges schade voor een extra bedrag gelijk aan 3% van uw schade gedaan terwijl het actief was en spatten 10% van hun schade op nabijgelegen vijanden, gereduceerd tot meer dan 5 doelen.\n\nHerstel\nWanneer uw Dryad vervaagt, genezen uw volgende 2 Swiftmends voor een extra bedrag gelijk aan 5% van uw genezing gedaan terwijl het actief was en spetteren 25% van hun genezing op nabijgelegen bondgenoten, gereduceerd tot meer dan 5 doelen."}
