MultiLanguageSpellData['nl'][1236972] = {name = "Zonne Wrath", additional_info = "Direct\n[q]Holy (Avenging Wrath)\nDe genezing en schade van Dawnlight wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra 10[10][10] sec.\n\nVergelding\nDawnlight's genezing en schade wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra [10][10] sec.\n\nBescherming\nDawnlight's genezing en schade wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra [10][10] sec."}
