MultiLanguageSpellData['nl'][1236989] = {name = "Maanlicht verzamelen", additional_info = "Direct\n[q]Balance\nOp impact, Starsurges gelanceerd door Starfire splitsen tot maximaal 3 extra doelen op 40% effectiviteit en verlenen een stapel van Gathering Moonlight. Gieten Furie van Elune of Volle Maan verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec.\n\nFeral, Guardian, Restauratie\nOp impact, Starsurges gelanceerd door Thrash splitsen tot maximaal 3 extra doelen op 20% effectiviteit en verlenen een stapel Gathering Moonlight. Afgietsel Maanstraal verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec."}
MultiLanguageSpellData['nl'][1236990] = {name = "Moonlight Suffusion", additional_info = "Direct\n[q]Balance\nOp impact, Starsurges gelanceerd door Starfire splitsen tot maximaal 3 extra doelen op 40% effectiviteit en verlenen een stapel van Gathering Moonlight. Gieten Furie van Elune of Volle Maan verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec.\n\nFeral, Guardian, Restauratie\nOp impact, Starsurges gelanceerd door Thrash splitsen tot maximaal 3 extra doelen op 20% effectiviteit en verlenen een stapel Gathering Moonlight. Afgietsel Maanstraal verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec."}
MultiLanguageSpellData['nl'][1236991] = {name = "Leegte verminderen", additional_info = "100 yd bereik\nDirect\n[q]Het nemen van schade heeft een grote kans om ervoor te zorgen dat u de essentie van nabijgelegen vijanden te verslinden, dealen 2116 Schaduw schade verdeeld tussen hen en u genezen voor 150% van de schade behandeld.\n\nDodelijke schade niet hoger dan 18656 in plaats daarvan herstelt u tot 20% gezondheid en reconstitueert u als onstabiele leegte voor 6 sec. Overtrof 50% gezondheid om de dood te stabiliseren en te voorkomen. Dit effect kan eenmaal per 8 minuten optreden. De Nucleus kan geen schade aanrichten tijdens het opladen."}
