MultiLanguageSpellData['nl'][1238693] = {name = "Voidglasscherven", additional_info = "100 yd bereik\nDirect\n[q]Uw spreuken hebben de kans om leegglas scherven te toveren, vijanden te snijden voor ( 474 * 1 ) Kosmische schade of om bondgenoten draaien om 1263 schade te absorberen voor maximaal 20 sec."}
MultiLanguageSpellData['nl'][1238696] = {name = "Demonsurge", additional_info = "Direct\n[q]Metamorfose nu ook [ Havoc : causes Demon's Bite to generate 15 additional Fury /\n\nVengeance\ngreatly empowers Soul Cleave and Spirit Bomb ]\nTerwijl de demon vorm actief is, de eerste cast van elk gemachtigd vermogen induceert een Demonsurge, waardoor u te exploderen met Fel energie, omgaan (330% van Attack Power) Brand schade aan nabijgelegen vijanden. Dealt verminderde schade boven 8 doelen."}
