MultiLanguageSpellData['nl'][1239714] = {name = "Soul Swipe", additional_info = "Melee-bereik\nDirect\n[q]Demonologie\nDe schade die je demonische ziel aanricht, wordt met 10% verhoogd.\n\nConsuming Demonic Core voedt de demonische entiteit in je, waardoor het verschijnt en [(240.402% of Spell Power) * 0.4] Schaduwschade aan je doel dealt.\n\nAfwikkeling\nDe schade die je demonische ziel aanricht, wordt met 10% verhoogd.\n\nHet consumeren van Nightfall voedt de demonische entiteit in je, waardoor het te verschijnen en deal (240,402% van Spell Power) Schaduw schade aan je doel."}
