MultiLanguageSpellData['nl'][1239744] = {name = "Wekelijkse activiteit", additional_info = "Direct\n[q]Het voltooien van deze zoektocht kan u belonen met een wekelijkse Fractured Spark of Starlight. Twee gebroken vonken kunnen worden gecombineerd tot een vonk van sterrenlicht, die wordt gebruikt door beroepen om krachtige wapens en Armor te creëren.\n\nAls je achterloopt op deze wekelijkse vonken, het invullen van andere max-level inhoud zoals Delves, Mythic Plus, Raids, Instanced PvP, en sommige outdoor evenementen kunnen u helpen inhalen.\n\nJe hebt deze week al je Fractured Spark of Starlight ontvangen."}
