MultiLanguageSpellData['nl'][1245357] = {name = "Adorned Northeron Gryphon", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De oudere gryphon renners en hoge sjamanen van de Northeron Wildhammer sierden vaak hun gryfons in sierlijke, gevederde stukken, wat hun rang en status aangeeft.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1245358] = {name = "High Shaman's Aerie Gryphon", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De oude Wildhammer sjamanen die voor het eerst gryphons tegenkwamen geloofden dat ze elementaire geesten in sterfelijke vorm waren. Deze ontmoeting zou voor eeuwig indrukken op de Wildhammer clan voor de komende generaties.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1245359] = {name = "Cinder-Plumed Highland Gryphon", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Volgens de legende van Wildhammer wordt aangenomen dat het oranje verenkleed op gryphons een erfelijke eigenschap is die van hun elementaire voorouders is doorgegeven.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1245360] = {name = "Raket", additional_info = nil}
MultiLanguageSpellData['nl'][1245361] = {name = "Emberwing Sky Guide", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Vanaf de uitlopers van Khaz Modan volgden we zijn door de zon verlichte vleugels - een in het noorden gebonden fakkel over de donkere zomerhemel.\" - De pelgrimage van de Eerste Wildsage\nHandelspost"}
MultiLanguageSpellData['nl'][1245370] = {name = "Ornery Breezestider", additional_info = "1.5 sec gegoten\n[q]Summons en verwerpt uw Ornery Breezestrider.\n[q]\"Deze talbuk is een koppige, koppige berg, zelfs na het leren kennen van zijn ruiter. Rijders pas op.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1245376] = {name = "Arcane Hunter", additional_info = "Direct\n[q]Uw schadelijke spreuken en gevarieerde vermogens Critical Strike's hebben een hoge kans om u Arcane Hunter tot 5 keer, het verhogen van uw Critical Strike rating met 14 per stack voor 8 sec."}
MultiLanguageSpellData['nl'][1245377] = {name = "Verhuizers inschakelen", additional_info = "Direct\n[q]So'azmi zet paren Relocators in om zijn vijanden te verwarren.\nWanneer een speler een Relocator aanraakt, worden ze onmiddellijk geteleporteerd naar de andere Relocator die er mee overeenkomt."}
