MultiLanguageSpellData['nl'][1245384] = {name = "Fel Inferno", additional_info = "Onbeperkt bereik\nDirect\n[q]Velaryn wreathes the arena in flame, veroorzaken 843230 Brand schade aan alle spelers en een extra 182700 Brand schade elke 0,5 sec voor 15 sec wanneer elke pilaar van de inferno wordt gemaakt. Dit effect stapelt zich op.\n\nDe vlam brengt 8435981 Brand elke 1 seconde schade toe aan spelers die in de vuurstorm stappen."}
MultiLanguageSpellData['nl'][1245385] = {name = "Aanraking van Malice", additional_info = "100 yd bereik\nDirect\n[q]Uw en uw volgelingen' schadelijke spreuken en vermogens periodiek toepassen Fel Aangeraakt aan vijanden. De helse dreadlord die door Twisted Crusade werd opgeroepen, slaat altijd kritiek op Fel Touched vijanden.\n\n\nFel Touched\nElke 4 seconden barsten de doelwitten... en beschadigen de vijanden in de buurt... voor 3% van de schade die de laatste 4 seconden heeft veroorzaakt.\n(Proc-kans: 33%, 2s afkoeling)"}
