MultiLanguageSpellData['nl'][1248603] = {name = "Killing Spree", additional_info = "10 yd bereik\nDirect\nVereist Melee wapen\n[q]Finishing beweging die een barrage van schoten loslaat, willekeurige vijanden binnen 8 meter slaan voor fysieke schade. Het aantal stakingen is per combinatiepunt gestegen.\n\nHerstelt 1 combopunt per 0,50 sec.\n\n1 punt: [((225% of Attack Power) + (225% of Attack Power)) * 2] gedeeld door 0,50 sec\n2 punten: [((225% of Attack Power) + (225% of Attack Power)) * 3] meer dan 1,00 sec\n3 punten: [((225% of Attack Power) + (225% of Attack Power)) * 4] gedeeld door 1,50 sec.\n4 punten: [((225% of Attack Power) + (225% of Attack Power)) * 5] gedeeld door 2,00 sec\n5 punten: [((225% of Attack Power) + (225% of Attack Power)) * 6] gedeeld door 2,50 sec\n[ 6 points: [((225% of Attack Power) + (225% of Attack Power)) * 7] over 3,00 sec] [ 7 points: [((225% of Attack Power) + (225% of Attack Power)) * 8] over 3,50 sec]"}
