MultiLanguageSpellData['nl'][1249462] = {name = "Deal: Kartel Zo", additional_info = "Direct\n[q]Maak een deal met Kartel Zo die je het recht geeft om jezelf een van hen te noemen (voor een week).\n\nOorlogsbandcontract\nJe mag maar een deal maken met één kartel per week. Dit effect wordt gedeeld over uw Warband."}
MultiLanguageSpellData['nl'][1249463] = {name = "[q3]Deal: Kartel", additional_info = "3,5 sec gegoten\nReagentia:\nVerse Parchment, Manaformed Instrument, Abricate Ink (25)\nManaforge Vandalen\nHerinnering:\n8\nLocatie:\nSchaduwpunt\n\n[q3]Deal: Kartel\n[q2]Gebruik: Maak een deal met Kartel Zo dat verdient u het recht om jezelf een van hen (voor een week).\n\nOorlogsbandcontract\nJe mag maar een deal maken met één kartel per week. Dit effect wordt gedeeld over uw Warband.\n70\n[q]\"Een korte termijn \"contract\" opgesteld door Scribes die een Warband's trouw aan een makelaar kartel toezegt.\""}
MultiLanguageSpellData['nl'][1249464] = {name = "Boon van Elune", additional_info = "Direct\n[q]Marksmanschap\nSnelle brandschade steeg met 25%. Wanneer Lunar Storm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Aimed Shots om Arcane schade te dealen en hun schade verhoogd met 10%.\n\nBeast Mastery, Overleving\nDe schade aan de bom is met 10% toegenomen. Wanneer Maanstorm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Wildfire Bombs om Arcane schade te behandelen en hun initiële schade verhoogd met 150%."}
MultiLanguageSpellData['nl'][1249465] = {name = "Deal: Kartel Ba", additional_info = "Direct\n[q]Maak een deal met Kartel Ba die je het recht geeft om jezelf één van hen te noemen (voor een week).\n\nOorlogsbandcontract\nJe mag maar een deal maken met één kartel per week. Dit effect wordt gedeeld over uw Warband."}
