MultiLanguageSpellData['nl'][1250915] = {name = "Timewarped Wyrmtongue", additional_info = "Direct\n[q]Time-shifted in a wyrmtongue, genegeerd door de meeste vijanden.\nBeweging Speed steeg met 60%.\n\nIn staat om te zien Motes of Bronze op Argus: het verzamelen van Motes of Bronze zal verhogen uw beweging Speed en Bronze winsten, stapelen totdat dit effect slijt.\n\nGevecht annuleert dit effect."}
