MultiLanguageSpellData['nl'][1251255] = {name = "Treetop Highmountain Eagle", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De majestueuze adelaar is een symbool van trots voor de Highmountain stammen. Het vermogen van dit grote beest om tauren op hun Backs te dragen spreekt tot de pure Strength en de grootte van de schepselen van High Mountain.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251257] = {name = "Leyfrost Manasaber", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af."}
MultiLanguageSpellData['nl'][1251259] = {name = "Toevoegen Keystone Affix: Tyrannisch versterkt", additional_info = "Direct\n[q]Voeg het Tyrannisch versterkte affix toe aan een Mythic Keystone."}
MultiLanguageSpellData['nl'][1251264] = {name = "Nightwell Manasaber", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af."}
MultiLanguageSpellData['nl'][1251265] = {name = "Arcberry Manasaber", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Genoemd naar hun gelijkenis met de heldere bessen gemaakt tot arckine, deze trotse katten hebben een scherp bewustzijn van de leylijnen die onder hen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251266] = {name = "Droombolt", additional_info = "30 yd bereik\n{2 sec cast} {3 sec cooldown}\n[q]Hurl aarde op een vijand dealen 150 Fysieke schade."}
MultiLanguageSpellData['nl'][1251279] = {name = "Fel-Scarred Mana Ray", additional_info = "1.5 sec gegoten\n[q]Summons en verwerpt een Fel-Scarred Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"Overleven op Argus is geen gemakkelijke taak. Zijn Leathery verbergt littekens door fel corruptie, deze mana straal is gevoelig voor aanvallen, meer dan normaal.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251281] = {name = "Bloodtooth Mana Ray", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat een Bloodtooth Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"De verbrijzeling van Argus dreef dit ras van mana straal tot bloeddorstig. Het bevindt zich nu op het corrupte bloed van alle wezens waar het zijn vele tanden in kan laten zinken.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251283] = {name = "Albino Mana Ray", additional_info = "1.5 sec gegoten\n[q]Summons wijst een Albino Mana Ray af. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"De verbrijzeling van Argus zorgde ervoor dat de manastralen muteren en zich aanpassen aan hun omgeving. Sommigen van hen lieten hun pigmenten achter ten gunste van Strengthening hun zintuigen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251284] = {name = "Luminous Mana Ray", additional_info = "1.5 sec gegoten\n[q]Summons wijst een Luminous Mana Ray af. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"Mana stralen kunnen een heldere gloed uitstralen om prooi te lokken.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251292] = {name = "Plaatsing", additional_info = nil}
MultiLanguageSpellData['nl'][1251295] = {name = "Twilight Courser", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Om roofdieren te ontwijken, verduistert deze cursus zijn hoorn terwijl hij zich verbergt en flitst met schitterende stralen wanneer hij wordt uitgelokt.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251297] = {name = "Gouden Sunrunner", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Deze vrije geest geniet van lange drafjes op het strand en zwerft door verschillende bloemenvelden.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251298] = {name = "Turquoise Courser", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Genoemd om zijn Unique gekleurd ogen die lijken te doordringen uw ziel, de turquoise cursusgever toont meer intelligentie dan haar droomrunner neven en staat bekend als een uitstekende beoordeling van karakter.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251300] = {name = "Gloomdark Nachtmerrie", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Aangeraakt door de Emerald Nightmare, is de aanwezigheid van dit schepsel in zijn dromen een voorteken van ongeluk. Om er een te zien terwijl wakker een absolute catastrofe voorspelt.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251305] = {name = "Bonesteed of Triumph", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Een goed oorlogspaard is trouw aan zijn botten. Na zijn sterfelijke spiraal te hebben afgeschud, is dit paard een voorteken van gedurfde verovering.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251307] = {name = "Bonesteed of Bloodshed", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Een goed oorlogspaard is trouw aan zijn botten. Dit paard is een voorteken van eeuwige strijd.\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251309] = {name = "Bonesteed of Plague", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Een goed oorlogspaard is trouw aan zijn botten. Na het afschudden van zijn sterfelijke spiraal, is dit paard een voorteken van ziekte en lijden.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251311] = {name = "Bonesteed of Oblivion", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Een goed oorlogspaard is trouw aan zijn botten. Dit paard is een voorteken van schaarste en dood.\nWereldevenement:\nWoW Remix: Legioen"}
