MultiLanguageSpellData['nl'][1251396] = {name = "Longhorned Sable Talbuk", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De talkbuks van Argus zijn gegroeid lange, grove bont van briljante kleuren die de tinten van hun gebroken planeet weerspiegelt.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251397] = {name = "Garnet Ruinstrider", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Uitgerust met stevige barden, dragen Argussiaanse ruinestriders zonder angst hun ruiters over het gebroken afval van Argus en daarbuiten.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251398] = {name = "Longhorned Bleakhoof Talbuk", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Gesneeuwd door de chaos van tientallen jaren conflict, is dit fel-infused paard een perfecte match voor een onverschrokken avonturier.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251399] = {name = "Longhorned Argussian Talbuk", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Enkele talbuks wisten ongedeerd te blijven ondanks de uitbuiting van hun thuiswereld door het Legioen. Hun vasthoudendheid past bij een edel paard.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251400] = {name = "Longhorned Beryl Talbuk", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Deze wilde talbuk gevonden tussen de ruïnes van Argus heeft het overleefd en volgehouden door decennia van strijd.\"\nWereldevenement:\nWoW Remix: Legioen"}
