MultiLanguageSpellData['nl'][1251553] = {name = "Etherische bescherming", additional_info = "Direct\nOngeveer 2 procs per minuut\n[q]Uw spreuken en vermogens hebben een grote kans om de energie om u heen samen te voegen, waardoor u een Shield krijgt die de schade tot een drempel van 20% vermindert.\n\nBij een daling van minder dan 40% gezondheid, krijgen dit effect bij 500% effectiviteit. Dit effect kan slechts eenmaal per 6 minuten optreden.\n(100ms afkoeling)"}
