MultiLanguageSpellData['nl'][1252185] = {name = "Infusie pylonen", additional_info = "50 yd bereik\nDirect\n[q]De arcane pylonen van de kamer pompen energie in Loom'ithar via arcane stralen, waardoor een overtollig Nova op contact.\n\nSpelers staan binnen de straal blokkeren zijn pad, lijden 606071 Arcane schade en het verkrijgen van een toepassing van Hyper Infusion elke 1 sec. Dit effect stapelt zich op."}
MultiLanguageSpellData['nl'][1252190] = {name = "Vlucht van de Val'kyr", additional_info = "[q]Vindicator's Oordeel zegent tot 5 nabijgelegen bondgenoten om gedurende 12 sec door val'kyr te worden bewaakt.\n\nTijdens de bewaking worden fatale aanvallen onderschept door de val'kyr... en helen het doelwit tot hun maximale gezondheid. Kan niet activeren op hetzelfde doel vaker dan één keer per 8 min."}
