MultiLanguageSpellData['nl'][1252193] = {name = "Odyn's Chosen", additional_info = "Onbeperkt bereik\nDirect\n[q]Vindicator's Oordeel zegent tot 5 nabijgelegen bondgenoten om gedurende 12 sec door val'kyr te worden bewaakt.\n\nTijdens de bewaking worden fatale aanvallen onderschept door de val'kyr... en helen het doelwit tot hun maximale gezondheid. Kan niet activeren op hetzelfde doel vaker dan één keer per 8 min."}
MultiLanguageSpellData['nl'][1252196] = {name = "Aanbod aanvragen", additional_info = "Direct\n[q]Je hebt je aanbod aan een Timewarped Obelisk niet voltooid. Herstel effecten van Timewarped Obelisks zijn aanzienlijk verminderd."}
MultiLanguageSpellData['nl'][1252198] = {name = "Bevelen om te verfraaien", additional_info = "[q]Na het gebruik van het Oordeel van Vindicator, wordt het de Fray.\n\nVoer de Fray in\nRush voorwaarts met ijverige macht, alle vijanden op jullie pad slaand voor [(168% Attack/Spell Power)] Heilige schade.\n\nWordt lichtgebonden passage na gebruik.\n\nLichtgebonden doorgang\nStap in een straal van licht die tot [(168% Attack/Spell Power)] Heilige schade aan vijanden en tot [(168% Attack/Spell Power)] genezing aan bondgenoten binnen 6 yds, teleporteert u Backwards 20 yds of tot het bereiken van een obstakel.\n\nOok terwijl Lightforged, krijg je Echo van Licht.\n\nEcho van licht\nHeilig licht straalt van je af en gaat elke 3 seconden samen in motels. Het aanraken van de motel deals [(168% Attack/Spell Power)] Heilige schade aan nabijgelegen vijanden of herstelt [(168% Attack/Spell Power)] gezondheid aan nabijgelegen bondgenoten binnen 60 yds."}
