MultiLanguageSpellData['nl'][1255154] = {name = "Afsluiten catch up", additional_info = "Direct\n[q]Als u verdwaald bent, probeer dan Peruse Tome te teleporteren naar het juiste gebied.\n\nHet verlaten van Catch Up teleporteert u Back naar uw hoofdstad. U zult in staat zijn om deze Catch Up Campaign opnieuw te hervatten op elk moment, tenzij u een andere start.\n\nWilt u doorgaan?"}
MultiLanguageSpellData['nl'][1255155] = {name = "Afsluiten catch up", additional_info = "Direct\n[q]Eind de Lorewalking Campaign en keer terug naar uw hoofdstad."}
MultiLanguageSpellData['nl'][1255159] = {name = "Mechanisch Prototype Panther MK-0", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"Toen Gadgetzan burgers het ondergrondse lab van het paleis van Gazlowe openden, stikten de gebrul van gekooide beesten. Ondermijn de tech gevechtsmodules op deze panters, waardoor bovenmenselijke Strength en Speed ontstaan. Rustbolt ingenieurs herprogrammeerden ze uitsluitend voor krijgers die campagne voeren in K'aresh. Vergeet niet om modules te ruilen op het Morphing Forum voor de implementatie.\"\nIn-Game Shop"}
MultiLanguageSpellData['nl'][1255165] = {name = "Raadpleeg de Tome", additional_info = "{Instant} {4 sec cooldown}\n[q]Query de Tome over waar te gaan volgende of voor meer informatie."}
MultiLanguageSpellData['nl'][1255179] = {name = "Staal Prototype Panther MK-0", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze mount af.\n[q]\"De eerste Steel Horde soldaten die de Dark Portal overstaken, veroverden een woeste nachtzwaard. Blackrock ambachtslieden bewapenden het met magma Armor, het transformeren tot een gevechtswapen. Krijgers kunnen haar onderdelen aanpassen op het Morphing Forum om hun vechtstijl aan te passen en het slagveld te domineren.\"\nIn-Game Shop"}
