MultiLanguageSpellData['nl'][1255245] = {name = "Twilight Slash", additional_info = "Onbeperkt bereik\nDirect\n[q]De Oneindige Doder stapt door de schemering te verschijnen achter hun doel en slash, het toebrengen van 2 fysieke schade en bloeden ze voor een extra 0 fysieke schade elke 1,5 sec voor 9 sec."}
MultiLanguageSpellData['nl'][1255246] = {name = "Starspark Netherdrake", additional_info = "1.5 sec gegoten\n[q]Summons wijst deze vliegende berg af.\n[q]\"Nadat je naar het einde van Outland en verder vloog, werd de onderwaterdrake uiteindelijk ook naar de blauwe lucht van Azeroth getrokken.\"\nBevordering:\nBrandende kruistocht Klassiek"}
MultiLanguageSpellData['nl'][1255264] = {name = "Felscorned Vilebrood Vanquisher", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat uw Felscorned Vilebrood Vanquisher. Deze mount is alleen beschikbaar voor Death Knights.\n[q]\"Deze vliegende samensmelting van de krachten van de dood en kiel doorbort de lucht met een bone-chilling krijs.\"\nWereldevenement:\nWoW Remix: Legioen"}
