MultiLanguageSpellData['nl'][1255456] = {name = "Felscorned Wolfhawk", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat uw Felscorned Wolfhawk. Deze berg is alleen beschikbaar voor Hunters.\n[q]\"Deze Wolfhawk, gesneeuwd door de oorlog op de Broken Eilanden, verdient een goed thuis.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1255463] = {name = "Archmage's Felscorned Disc", additional_info = "1.5 sec gegoten\n[q]Summons en verwerpt uw aartsmage's Felscorned Disc. Deze mount is alleen beschikbaar voor Mages.\n[q]\"Sommige magiërs zeggen dat felmagies \"vluchtig\" of \"corrupt\" of \"verboden\" zijn. Sommigen hebben het mis.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1255467] = {name = "Felscorned Grandmaster's Companion", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat uw Felscorned Grandmaster's Companion. Deze mount is alleen beschikbaar voor Monniken.\n[q]\"Een verwrongen gezicht van een geliefde metgezel.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1255471] = {name = "Felscorned Highlord's Charger", additional_info = "1.5 sec gegoten\n[q]Summons en ontslaat uw Felscorned Highlord's Charger. Deze mount is alleen beschikbaar voor Paladins.\n[q]\"Dit paard is onherroepelijk getekend door de corrupte magie van het Legioen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1255475] = {name = "High Priest's Felscorned Seeker", additional_info = "1.5 sec gegoten\n[q]Summons en verwerpt de Felscorned Seeker van uw Hogepriester. Deze mount is alleen beschikbaar voor Priesters.\n[q]\"Deze fel-infused gevederde vriend flapt zijn vleugels in een frenetic tempo te blijven ver boven de razernij hieronder.\"\nWereldevenement:\nWoW Remix: Legioen"}
